export default ReinforcementOptimizer;

import React, { useEffect, useState } from 'react';
import { UserPlus, Mail } from 'lucide-react';
import { useAuth } from '../../hooks/useAuth';
import {
  assignEmployeeToProject,
  createEmployeeInvite,
  employeeInviteLoginHref,
  employeeInviteSignupHref,
  fetchAssignmentsForProject,
  fetchPendingInvites,
  sendEmployeeInviteEmail,
} from '../../services/employeeService';
import { fetchTeamProfiles, DEFAULT_PROFILE_DISPLAY_NAME } from '../../services/profileService';
import type { EmployeeInvite, Profile } from '../../types/fieldPlanner';
import Card from '../ui/Card';
import Input from '../ui/Input';
import Select from '../ui/Select';
import Button from '../ui/Button';
import { useProjectStore } from '../../store';

export default function EmployeeManagement() {
  const { user } = useAuth();
  const { projects } = useProjectStore();
  const [invites, setInvites] = useState<EmployeeInvite[]>([]);
  const [team, setTeam] = useState<Profile[]>([]);
  const [email, setEmail] = useState('');
  const [role, setRole] = useState('employee');
  const [assignProjectId, setAssignProjectId] = useState('');
  const [assignEmployeeId, setAssignEmployeeId] = useState('');
  const [message, setMessage] = useState<string | null>(null);
  const [busy, setBusy] = useState(false);

  const reload = async () => {
    if (!user) return;
    const [inv, members] = await Promise.all([
      fetchPendingInvites(user.id),
      fetchTeamProfiles(user.id),
    ]);
    setInvites(inv);
    setTeam(members);
  };

  useEffect(() => {
    void reload();
  }, [user]);

  const handleInvite = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user || !email.trim()) return;
    setBusy(true);
    setMessage(null);
    try {
      const invite = await createEmployeeInvite(user.id, email, role as import('../../types/fieldPlanner').UserRole);
      const signupLink = employeeInviteSignupHref(invite.token);
      try {
        const result = await sendEmployeeInviteEmail(invite.id, {
          siteUrl: window.location.origin,
        });
        const link = result.inviteLink || signupLink;
        if (result.existingUser) {
          setMessage(
            `Account already exists for ${email}. Share this login link: ${result.inviteLink || employeeInviteLoginHref(invite.token)}`,
          );
        } else {
          setMessage(`Invite email sent to ${email}. Backup link: ${link}`);
        }
      } catch (err) {
        setMessage(
          `Invite created. Share this signup link: ${signupLink}${
            err instanceof Error ? ` (${err.message})` : ''
          }`,
        );
      }
      setEmail('');
      await reload();
    } catch (err) {
      setMessage(err instanceof Error ? err.message : 'Failed to send invite');
    } finally {
      setBusy(false);
    }
  };

  const handleAssign = async () => {
    if (!user || !assignProjectId || !assignEmployeeId) return;
    setBusy(true);
    try {
      await assignEmployeeToProject(assignEmployeeId, assignProjectId, user.id);
      setMessage('Employee assigned to project');
      await fetchAssignmentsForProject(assignProjectId);
    } catch (err) {
      setMessage(err instanceof Error ? err.message : 'Assignment failed');
    } finally {
      setBusy(false);
    }
  };

  return (
    <div className="space-y-6 max-w-3xl">
      <Card className="p-6 bg-white/95 dark:bg-slate-800/95">
        <h2 className="text-lg font-semibold mb-4 flex dark:text-white items-center gap-2">
          <UserPlus className="h-5 w-5 text-cyan-600" />
          Invite team member
        </h2>
        <form onSubmit={(e) => void handleInvite(e)} className="space-y-4">
          <Input
            label="Email"
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
          />
          <Select
            label="Role"
            value={role}
            onChange={setRole}
            options={[
              { value: 'employee', label: 'Employee' },
              { value: 'foreman', label: 'Foreman' },
              { value: 'project_manager', label: 'Project Manager' },
            ]}
          />
          <Button type="submit" disabled={busy} icon={<Mail className="h-4 w-4" />}>
            Send invite
          </Button>
        </form>
        {message && <p className="mt-3 text-sm text-cyan-700 dark:text-cyan-300">{message}</p>}
      </Card>

      <Card className="p-6 bg-white/95 dark:bg-slate-800/95 dark:text-white">
        <h2 className="text-lg font-semibold mb-4">Pending invites</h2>
        {invites.length === 0 ? (
          <p className="text-sm text-slate-500">No pending invites.</p>
        ) : (
          <ul className="space-y-2">
            {invites.map((inv) => (
              <li key={inv.id} className="text-sm text-slate-600 dark:text-slate-300">
                <span>
                  {inv.email} · {inv.role}
                </span>
                <div className="mt-1 break-all text-xs text-slate-500 dark:text-slate-400">
                  {employeeInviteSignupHref(inv.token)}
                </div>
              </li>
            ))}
          </ul>
        )}
      </Card>

      <Card className="p-6 bg-white/95 dark:bg-slate-800/95 dark:text-white">
        <h2 className="text-lg font-semibold mb-4">Assign to project</h2>
        <div className="space-y-4">
          <Select
            label="Employee"
            value={assignEmployeeId}
            onChange={setAssignEmployeeId}
            options={[
              { value: '', label: 'Select employee' },
              ...team.map((m) => ({
                value: m.id,
                label: m.displayName ?? DEFAULT_PROFILE_DISPLAY_NAME,
              })),
            ]}
          />
          <Select
            label="Project"
            value={assignProjectId}
            onChange={setAssignProjectId}
            options={[
              { value: '', label: 'Select project' },
              ...projects.map((p) => ({ value: p.id, label: p.name })),
            ]}
          />
          <Button onClick={() => void handleAssign()} disabled={busy}>
            Assign
          </Button>
        </div>
      </Card>

      <Card className="p-6 bg-white/95 dark:bg-slate-800/95 dark:text-white">
        <h2 className="text-lg font-semibold mb-4">Team</h2>
        {team.length === 0 ? (
          <p className="text-sm text-slate-500">No team members yet.</p>
        ) : (
          <ul className="space-y-2">
            {team.map((m) => (
              <li key={m.id} className="text-sm">
                {m.displayName ?? DEFAULT_PROFILE_DISPLAY_NAME} · {m.role}
              </li>
            ))}
          </ul>
        )}
      </Card>
    </div>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import { MoreHorizontal } from 'lucide-react';
import type { PlannerTask } from '../../types/fieldPlanner';
import { updateTask } from '../../services/plannerService';
import type { TaskStatus } from '../../types/fieldPlanner';

interface TaskCardMenuProps {
  task: PlannerTask;
  isOwner: boolean;
  buckets: { id: string; title: string }[];
  onOpen: () => void;
  onRefresh: () => void;
  onCreateRfi: () => void;
  onCreateAdjustment: () => void;
}

const MENU_WIDTH = 208;
const MENU_MARGIN = 8;
const MENU_ITEM_HEIGHT = 36;

export default function TaskCardMenu({
  task,
  isOwner,
  buckets,
  onOpen,
  onRefresh,
  onCreateRfi,
  onCreateAdjustment,
}: TaskCardMenuProps) {
  const [open, setOpen] = useState(false);
  const [position, setPosition] = useState<{ top: number; left: number } | null>(null);
  const buttonRef = useRef<HTMLButtonElement | null>(null);
  const menuRef = useRef<HTMLDivElement | null>(null);

  const actionCount = useMemo(() => {
    const moveCount = isOwner ? buckets.filter((b) => b.id !== task.bucketId).length : 0;
    return 1 + (task.status !== 'Completed' ? 1 : 0) + moveCount + 2;
  }, [buckets, isOwner, task.bucketId, task.status]);

  const updatePosition = () => {
    const rect = buttonRef.current?.getBoundingClientRect();
    if (!rect) return;

    const estimatedHeight = Math.min(actionCount * MENU_ITEM_HEIGHT + 8, 320);
    const spaceBelow = window.innerHeight - rect.bottom - MENU_MARGIN;
    const opensUp = spaceBelow < estimatedHeight && rect.top > estimatedHeight;
    const top = opensUp
      ? Math.max(MENU_MARGIN, rect.top - estimatedHeight - MENU_MARGIN)
      : Math.min(rect.bottom + MENU_MARGIN, window.innerHeight - MENU_MARGIN);
    const left = Math.min(
      Math.max(MENU_MARGIN, rect.right - MENU_WIDTH),
      window.innerWidth - MENU_WIDTH - MENU_MARGIN,
    );

    setPosition({ top, left });
  };

  const openMenu = () => {
    window.dispatchEvent(new CustomEvent('planner-task-menu-open', { detail: task.id }));
    updatePosition();
    setOpen(true);
  };

  const closeMenu = () => setOpen(false);

  useEffect(() => {
    if (!open) return;

    const handlePointerDown = (event: PointerEvent) => {
      const target = event.target as Node;
      if (buttonRef.current?.contains(target) || menuRef.current?.contains(target)) return;
      closeMenu();
    };

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === 'Escape') closeMenu();
    };

    const handleOtherMenuOpen = (event: Event) => {
      const detail = (event as CustomEvent<string>).detail;
      if (detail !== task.id) closeMenu();
    };

    window.addEventListener('pointerdown', handlePointerDown);
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('resize', updatePosition);
    window.addEventListener('scroll', updatePosition, true);
    window.addEventListener('planner-task-menu-open', handleOtherMenuOpen);

    return () => {
      window.removeEventListener('pointerdown', handlePointerDown);
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('resize', updatePosition);
      window.removeEventListener('scroll', updatePosition, true);
      window.removeEventListener('planner-task-menu-open', handleOtherMenuOpen);
    };
  }, [open, task.id, actionCount]);

  const markComplete = async () => {
    await updateTask(task.id, { status: 'Completed' as TaskStatus });
    onRefresh();
    closeMenu();
  };

  const moveToBucket = async (bucketId: string) => {
    await updateTask(task.id, { bucketId });
    onRefresh();
    closeMenu();
  };

  const menu =
    open && position
      ? createPortal(
          <div
            ref={menuRef}
            className="fixed z-[9999] max-h-[min(20rem,calc(100dvh-1rem))] w-52 overflow-y-auto rounded-xl border border-slate-200 bg-white py-1 text-slate-900 shadow-xl dark:border-slate-700 dark:bg-slate-900 dark:text-slate-100"
            style={{ top: position.top, left: position.left }}
            onClick={(e) => e.stopPropagation()}
          >
            <button
              type="button"
              className="flex w-full items-center gap-2 px-4 py-2 text-left text-sm hover:bg-slate-100 dark:hover:bg-slate-800"
              onClick={() => {
                closeMenu();
                onOpen();
              }}
            >
              Open
            </button>
            {task.status !== 'Completed' && (
              <button
                type="button"
                className="flex w-full items-center gap-2 px-4 py-2 text-left text-sm hover:bg-slate-100 dark:hover:bg-slate-800"
                onClick={() => void markComplete()}
              >
                Mark complete
              </button>
            )}
            {isOwner &&
              buckets
                .filter((b) => b.id !== task.bucketId)
                .map((b) => (
                  <button
                    key={b.id}
                    type="button"
                    className="flex w-full items-center gap-2 px-4 py-2 text-left text-sm hover:bg-slate-100 dark:hover:bg-slate-800"
                    onClick={() => void moveToBucket(b.id)}
                  >
                    Move to {b.title}
                  </button>
                ))}
            <button
              type="button"
              className="flex w-full items-center gap-2 px-4 py-2 text-left text-sm hover:bg-slate-100 dark:hover:bg-slate-800"
              onClick={() => {
                closeMenu();
                onCreateRfi();
              }}
            >
              Create RFI
            </button>
            <button
              type="button"
              className="flex w-full items-center gap-2 px-4 py-2 text-left text-sm hover:bg-slate-100 dark:hover:bg-slate-800"
              onClick={() => {
                closeMenu();
                onCreateAdjustment();
              }}
            >
              Create FAR
            </button>
          </div>,
          document.body,
        )
      : null;

  return (
    <div className="absolute right-1 top-1 z-10">
      <button
        ref={buttonRef}
        type="button"
        onClick={(e) => {
          e.stopPropagation();
          if (open) closeMenu();
          else openMenu();
        }}
        className={`rounded p-1 transition hover:bg-slate-100 dark:hover:bg-slate-700 ${
          open ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'
        }`}
        aria-label="Task menu"
        aria-expanded={open}
        aria-haspopup="menu"
        data-menu-open={open}
      >
        <MoreHorizontal className="h-4 w-4 text-gray-500" />
      </button>
      {menu}
    </div>
  );
}

import { useState, type ReactNode } from 'react';
import { format } from 'date-fns';
import type { ProjectDocumentRow } from '../../../services/projectDocumentService';
import PlannerBuilderDocumentRow from '../PlannerBuilderDocumentRow';
import ProjectRecordActions from '../ProjectRecordActions';
import {
  PLANNER_MUTED,
  PLANNER_TABLE,
  PLANNER_TABLE_HEAD,
  PLANNER_TABLE_ROW,
  PLANNER_TABLE_ROW_HIGHLIGHT,
  PLANNER_TABLE_WRAPPER,
} from '../plannerTheme';

/** Friendly table date (e.g. Jun 4, 2026). Accepts ISO timestamps and yyyy-MM-dd. */
export function formatDocDate(iso: string | undefined): string {
  if (!iso) return '—';
  const trimmed = iso.trim();
  if (!trimmed) return '—';
  try {
    let d = new Date(trimmed);
    if (Number.isNaN(d.getTime()) && /^\d{4}-\d{2}-\d{2}$/.test(trimmed)) {
      d = new Date(`${trimmed}T12:00:00`);
    }
    if (Number.isNaN(d.getTime())) return '—';
    return format(d, 'MMM d, yyyy');
  } catch {
    return '—';
  }
}

export function formatSigningMeta(doc: ProjectDocumentRow): string {
  const status = doc.signing_status ?? 'draft';
  if (status === 'signed') return 'Signed';
  if (status === 'sent' || status === 'viewed') return 'Awaiting client signature';
  if (status === 'declined') return 'Declined';
  if (status === 'void') return 'Void';
  return `Draft · v${doc.latest_version_number}`;
}

export function BuilderDraftsTable({
  docs,
  projectId,
  empty,
  onDeleted,
  onOpenDrawer,
}: {
  docs: ProjectDocumentRow[];
  projectId: string;
  empty: string;
  onDeleted: () => void;
  onOpenDrawer?: (documentId: string) => void;
}) {
  const [deleteConfirmDocId, setDeleteConfirmDocId] = useState<string | null>(null);

  if (docs.length === 0) {
    return <p className={`${PLANNER_MUTED} py-2 text-sm`}>{empty}</p>;
  }
  return (
    <div className={PLANNER_TABLE_WRAPPER}>
      <table className={PLANNER_TABLE}>
        <thead>
          <tr className={PLANNER_TABLE_HEAD}>
            <th className="px-4 py-3 font-semibold">Updated</th>
            <th className="px-4 py-3 font-semibold">Title</th>
            <th className="px-4 py-3 font-semibold">Number / Status</th>
            <th className="px-4 py-3 font-semibold text-right">Actions</th>
          </tr>
        </thead>
        <tbody>
          {docs.map((doc) => (
            <PlannerBuilderDocumentRow
              key={doc.id}
              doc={doc}
              projectId={projectId}
              onDeleted={() => {
                setDeleteConfirmDocId(null);
                onDeleted();
              }}
              onOpenDrawer={onOpenDrawer}
              deleteConfirm={{
                deleteConfirmActive: deleteConfirmDocId === doc.id,
                onDeleteRequest: () => setDeleteConfirmDocId(doc.id),
                onDeleteCancel: () => setDeleteConfirmDocId(null),
              }}
            />
          ))}
        </tbody>
      </table>
    </div>
  );
}

export function SimpleDocumentsTable({
  rows,
  empty,
  highlightId,
  buildHref,
  onOpenDrawer,
  primaryLabel = 'View / Update',
}: {
  rows: { id?: string; date: string; title: string; meta: string }[];
  empty: string;
  highlightId: string | null;
  buildHref: (id: string) => string;
