import { useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { format } from 'date-fns';
import type { FieldAdjustmentRequest } from '../../../../types/fieldPlanner';
import { FAR_STATUSES } from '../../../../types/fieldPlanner';
import type { ProjectDocumentRow } from '../../../../services/projectDocumentService';
import {
  FAR_WORKFLOW_STATUSES,
  partitionFarBuilderDocuments,
  resolveBuilderWorkflowStatusFromDoc,
} from '../../../../services/builderWorkflowStatus';
import { resolveFarDisplayNumber } from '../../../../services/projectRecordNumbering';
import PlannerBuilderDocumentRow from '../../PlannerBuilderDocumentRow';
import BuilderDocumentTableActions from '../../BuilderDocumentTableActions';
import ProjectRecordActions from '../../ProjectRecordActions';
import { contractBuilderToolHref } from '../../../../utils/plannerRoutes';
import { nameFromMap } from '../../../../services/profileService';
import Button from '../../../ui/Button';
import FarDetailDrawer from '../../../field/FarDetailDrawer';
import FieldRecordStatusBadge from '../../../field/FieldRecordStatusBadge';
import ProjectDocumentDrawer from '../../ProjectDocumentDrawer';
import {
  PLANNER_MUTED,
  PLANNER_TABLE,
  PLANNER_TABLE_HEAD,
  PLANNER_TABLE_WRAPPER,
} from '../../plannerTheme';
import { DocumentsPanelFootnote, PanelActionRow } from '../documentsPanelUtils';
import { useDocumentsSearchParams } from '../useDocumentsSearchParams';

const FAR_PRIORITY_OPTIONS = ['Low', 'Normal', 'High', 'Urgent'] as const;

interface Props {
  projectId: string;
  items: FieldAdjustmentRequest[];
  builderFarDrafts: ProjectDocumentRow[];
  nameMap: Map<string, string>;
  userId: string | undefined;
  isOwner: boolean;
  onReload: () => void;
  onProjectReload: () => void;
}

function formatBuilderDate(iso: string | undefined): string {
  if (!iso) return '—';
  try {
    return format(new Date(iso), 'MMM d, yyyy');
  } catch {
    return iso;
  }
}

function matchesBuilderSearch(doc: ProjectDocumentRow, search: string): boolean {
  if (!search) return true;
  const q = search.toLowerCase();
  return (
    doc.title.toLowerCase().includes(q) ||
    resolveFarDisplayNumber(doc).toLowerCase().includes(q)
  );
}

export default function FarsDocumentsPanel({
  projectId,
  items,
  builderFarDrafts,
  nameMap,
  userId,
  isOwner,
  onReload,
  onProjectReload,
}: Props) {
  const navigate = useNavigate();
  const { searchParams, mergeParams } = useDocumentsSearchParams();
  const highlightId = searchParams.get('adjustment');
  const [selectedId, setSelectedId] = useState<string | null>(highlightId);
  const [builderReviewDocId, setBuilderReviewDocId] = useState<string | null>(null);
  const [deleteConfirmDocId, setDeleteConfirmDocId] = useState<string | null>(null);
  const [search, setSearch] = useState('');
  const [priorityFilter, setPriorityFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState('');

  useEffect(() => {
    if (highlightId) setSelectedId(highlightId);
  }, [highlightId]);

  const builderParts = useMemo(() => partitionFarBuilderDocuments(builderFarDrafts), [builderFarDrafts]);

  const filterBuilder = (docs: ProjectDocumentRow[]) =>
    docs.filter((doc) => {
      if (!matchesBuilderSearch(doc, search)) return false;
      if (statusFilter) {
        const wf = resolveBuilderWorkflowStatusFromDoc(doc);
        if (wf !== statusFilter && doc.status !== statusFilter) return false;
      }
      return true;
    });

  const draftBuilder = useMemo(() => filterBuilder(builderParts.drafts), [builderParts.drafts, search, statusFilter]);
  const openBuilder = useMemo(() => filterBuilder(builderParts.open), [builderParts.open, search, statusFilter]);
  const closedBuilder = useMemo(
    () => filterBuilder(builderParts.closed),
    [builderParts.closed, search, statusFilter],
  );

  const filtered = useMemo(() => {
    return items.filter((a) => {
      if (search && !a.title.toLowerCase().includes(search.toLowerCase())) return false;
      if (statusFilter && a.status !== statusFilter) return false;
      return true;
    });
  }, [items, search, statusFilter]);

  const openCount = filtered.length + openBuilder.length;
  const closedCount = closedBuilder.length;

  const openDrawer = (id: string) => {
    setSelectedId(id);
    mergeParams({ adjustment: id });
  };

  const closeDrawer = () => {
    setSelectedId(null);
    mergeParams({ adjustment: null });
  };

  const renderBuilderFarRows = (docs: ProjectDocumentRow[]) =>
    docs.map((doc) => (
      <tr
        key={doc.id}
        className={`border-b border-slate-100 last:border-0 dark:border-slate-800 ${
          builderReviewDocId === doc.id ? 'bg-cyan-50/50 dark:bg-cyan-950/20' : ''
        }`}
      >
        <td className="px-3 py-2 font-mono text-xs">{resolveFarDisplayNumber(doc)}</td>
        <td className="max-w-[200px] px-3 py-2">
          <div className="truncate font-medium">{doc.title}</div>
          <div className="text-xs text-slate-500 dark:text-slate-400">Document Builder</div>
        </td>
        <td className="px-3 py-2 text-gray-500">—</td>
        <td className="px-3 py-2 text-gray-500">—</td>
        <td className="whitespace-nowrap px-3 py-2 text-gray-500">{formatBuilderDate(doc.updated_at)}</td>
        <td className="px-3 py-2">
          <FieldRecordStatusBadge status={resolveBuilderWorkflowStatusFromDoc(doc)} />
        </td>
        <td className="px-3 py-2 text-right">
          <BuilderDocumentTableActions
            doc={doc}
            projectId={projectId}
            onPrimary={setBuilderReviewDocId}
          />
        </td>
      </tr>
    ));

  const renderOpenClosedTable = (
    legacyRows: FieldAdjustmentRequest[],
    builderRows: ProjectDocumentRow[],
    empty: string,
  ) => {
    if (legacyRows.length === 0 && builderRows.length === 0) {
      return <p className={`${PLANNER_MUTED} py-2 text-sm`}>{empty}</p>;
    }
    return (
      <div className={PLANNER_TABLE_WRAPPER}>
        <table className={PLANNER_TABLE}>
          <thead className={PLANNER_TABLE_HEAD}>
            <tr>
              <th className="px-3 py-2">FAR #</th>
              <th className="px-3 py-2">Title</th>
              <th className="px-3 py-2">Priority</th>
              <th className="px-3 py-2">Submitted by</th>
              <th className="px-3 py-2">Date</th>
              <th className="px-3 py-2">Status</th>
              <th className="px-3 py-2" />
            </tr>
          </thead>
          <tbody>
            {legacyRows.map((adj) => (
              <tr
                key={adj.id}
                className={`border-b border-slate-100 last:border-0 dark:border-slate-800 ${
                  highlightId === adj.id ? 'bg-cyan-50/50 dark:bg-cyan-950/20' : ''
                }`}
              >
                <td className="px-3 py-2 font-mono text-xs">{adj.displayNumber ?? '—'}</td>
                <td className="max-w-[200px] truncate px-3 py-2 font-medium">{adj.title}</td>
                <td className="px-3 py-2 text-gray-500">—</td>
                <td className="px-3 py-2">{nameFromMap(nameMap, adj.submittedBy, '—')}</td>
                <td className="whitespace-nowrap px-3 py-2 text-gray-500">
                  {new Date(adj.createdAt).toLocaleDateString()}
                </td>
                <td className="px-3 py-2">
                  <FieldRecordStatusBadge status={adj.status} />
                </td>
                <td className="px-3 py-2 text-right">
                  <ProjectRecordActions
                    primary={{ label: 'View / Review', onClick: () => openDrawer(adj.id) }}
                  />
                </td>
              </tr>
            ))}
            {renderBuilderFarRows(builderRows)}
          </tbody>
        </table>
      </div>
    );
  };

  return (
    <>
      <PanelActionRow
        action={
          <Button
            variant="accent"
            size="sm"
            onClick={() =>
              navigate(
                contractBuilderToolHref(projectId, undefined, {
                  packKey: 'GENERIC_FAR',
                  documentType: 'far',
                }),
              )
            }
          >
            New FAR
          </Button>
        }
      />

      <div className="mb-4 flex flex-wrap gap-2">
        <input
          type="search"
          placeholder="Search title…"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="min-w-[160px] flex-1 rounded-lg border border-slate-300 px-3 py-2 text-sm dark:border-slate-600 dark:bg-slate-800"
        />
        <select
          value={priorityFilter}
          onChange={(e) => setPriorityFilter(e.target.value)}
          className="rounded-lg border border-slate-300 px-3 py-2 text-sm dark:border-slate-600 dark:bg-slate-800"
          aria-label="Filter by priority"
        >
          <option value="">All priorities</option>
          {FAR_PRIORITY_OPTIONS.map((p) => (
            <option key={p} value={p}>
              {p}
            </option>
          ))}
        </select>
        <select
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
          className="rounded-lg border border-slate-300 px-3 py-2 text-sm dark:border-slate-600 dark:bg-slate-800"
        >
          <option value="">All statuses</option>
          {FAR_STATUSES.map((s) => (
            <option key={s} value={s}>
              {s}
            </option>
          ))}
          {FAR_WORKFLOW_STATUSES.map((s) => (
            <option key={`wf-${s}`} value={s}>
              {s} (builder)
            </option>
          ))}
        </select>
      </div>

      <section className="mb-6">
        <h3 className="mb-2 text-xs font-semibold uppercase tracking-wide text-gray-500">
          Open FARs ({openCount})
        </h3>
        {renderOpenClosedTable(filtered, openBuilder, 'No open FARs.')}
      </section>

      <section className="mb-6">
        <h3 className="mb-2 text-xs font-semibold uppercase tracking-wide text-gray-500">
          Closed FARs ({closedCount})
        </h3>
        {renderOpenClosedTable([], closedBuilder, 'No closed FARs.')}
      </section>

      <section className="mt-8 border-t border-slate-200 pt-6 dark:border-slate-700">
        <h3 className="mb-2 text-xs font-semibold uppercase tracking-wide text-gray-500">
          FAR document drafts ({draftBuilder.length})
        </h3>
        {draftBuilder.length === 0 ? (
          <p className={`${PLANNER_MUTED} py-2 text-sm`}>
            No FAR documents in Draft workflow status. Use New FAR to create one.
          </p>
        ) : (
          <div className={PLANNER_TABLE_WRAPPER}>
            <table className={PLANNER_TABLE}>
              <thead className={PLANNER_TABLE_HEAD}>
                <tr>
                  <th className="px-4 py-3 font-semibold">Updated</th>
                  <th className="px-4 py-3 font-semibold">Title</th>
                  <th className="px-4 py-3 font-semibold">Number / Status</th>
                  <th className="px-4 py-3 font-semibold text-right">Actions</th>
                </tr>
              </thead>
              <tbody>
                {draftBuilder.map((doc) => (
                  <PlannerBuilderDocumentRow
                    key={doc.id}
                    doc={doc}
                    projectId={projectId}
                    onDeleted={() => {
                      setDeleteConfirmDocId(null);
                      onReload();
                    }}
                    onOpenDrawer={setBuilderReviewDocId}
                    deleteConfirm={{
                      deleteConfirmActive: deleteConfirmDocId === doc.id,
                      onDeleteRequest: () => setDeleteConfirmDocId(doc.id),
                      onDeleteCancel: () => setDeleteConfirmDocId(null),
                    }}
                  />
                ))}
              </tbody>
            </table>
          </div>
        )}
      </section>

      <ProjectDocumentDrawer
        documentId={builderReviewDocId}
        projectId={projectId}
        onClose={() => setBuilderReviewDocId(null)}
        onSaved={() => {
          onReload();
          onProjectReload();
        }}
      />

      {userId && (
        <FarDetailDrawer
          adjustmentId={selectedId}
          userId={userId}
          isOwner={isOwner}
          onClose={closeDrawer}
          onUpdated={() => {
            onReload();
            onProjectReload();
          }}
        />
      )}

      <DocumentsPanelFootnote />
    </>
  );
}

import { useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { format } from 'date-fns';
import type { RfiRequest } from '../../../../types/fieldPlanner';
import { RFI_PRIORITIES } from '../../../../types/fieldPlanner';
import { isRfiClosed } from '../../../../services/rfiService';
import type { ProjectDocumentRow } from '../../../../services/projectDocumentService';
import {
  partitionRfiBuilderDocuments,
  resolveBuilderWorkflowStatusFromDoc,
  RFI_WORKFLOW_STATUSES,
} from '../../../../services/builderWorkflowStatus';
import { resolveRfiDisplayNumber } from '../../../../services/projectRecordNumbering';
import PlannerBuilderDocumentRow from '../../PlannerBuilderDocumentRow';
import BuilderDocumentTableActions from '../../BuilderDocumentTableActions';
import ProjectRecordActions from '../../ProjectRecordActions';
import { contractBuilderToolHref } from '../../../../utils/plannerRoutes';
import { nameFromMap } from '../../../../services/profileService';
import Button from '../../../ui/Button';
import RfiDetailDrawer from '../../../field/RfiDetailDrawer';
import ProjectDocumentDrawer from '../../ProjectDocumentDrawer';
import FieldRecordStatusBadge from '../../../field/FieldRecordStatusBadge';
import { TaskPriorityBadge } from '../../TaskStatusBadge';
import {
  PLANNER_MUTED,
  PLANNER_TABLE,
  PLANNER_TABLE_HEAD,
  PLANNER_TABLE_WRAPPER,
} from '../../plannerTheme';
import { DocumentsPanelFootnote, PanelActionRow } from '../documentsPanelUtils';
import { useDocumentsSearchParams } from '../useDocumentsSearchParams';

interface Props {
  projectId: string;
  rfis: RfiRequest[];
  builderRfiDrafts: ProjectDocumentRow[];
  nameMap: Map<string, string>;
  userId: string | undefined;
  isOwner: boolean;
  onReload: () => void;
  onProjectReload: () => void;
}

function formatBuilderDate(iso: string | undefined): string {
  if (!iso) return '—';
  try {
    return format(new Date(iso), 'MMM d, yyyy');
  } catch {
    return iso;
  }
}

function matchesBuilderSearch(doc: ProjectDocumentRow, search: string): boolean {
  if (!search) return true;
  const q = search.toLowerCase();
  return (
    doc.title.toLowerCase().includes(q) ||
    (doc.document_number ?? '').toLowerCase().includes(q)
  );
}

export default function RfisDocumentsPanel({
  projectId,
  rfis,
  builderRfiDrafts,
  nameMap,
  userId,
  isOwner,
  onReload,
  onProjectReload,
}: Props) {
  const navigate = useNavigate();
  const { searchParams, mergeParams } = useDocumentsSearchParams();
  const highlightId = searchParams.get('rfi');
  const [selectedId, setSelectedId] = useState<string | null>(highlightId);
  const [builderReviewDocId, setBuilderReviewDocId] = useState<string | null>(null);
  const [deleteConfirmDocId, setDeleteConfirmDocId] = useState<string | null>(null);
  const [search, setSearch] = useState('');
  const [priorityFilter, setPriorityFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState('');

  useEffect(() => {
    if (highlightId) setSelectedId(highlightId);
  }, [highlightId]);

  const builderParts = useMemo(() => partitionRfiBuilderDocuments(builderRfiDrafts), [builderRfiDrafts]);

  const filterBuilder = (docs: ProjectDocumentRow[]) =>
    docs.filter((doc) => {
      if (!matchesBuilderSearch(doc, search)) return false;
      if (statusFilter) {
        const wf = resolveBuilderWorkflowStatusFromDoc(doc);
        if (wf !== statusFilter && doc.status !== statusFilter) return false;
      }
      return true;
    });

  const draftBuilder = useMemo(() => filterBuilder(builderParts.drafts), [builderParts.drafts, search, statusFilter]);
  const openBuilder = useMemo(() => filterBuilder(builderParts.open), [builderParts.open, search, statusFilter]);
  const closedBuilder = useMemo(
    () => filterBuilder(builderParts.closed),
    [builderParts.closed, search, statusFilter],
  );

  const filtered = useMemo(() => {
    return rfis.filter((r) => {
      if (search && !r.title.toLowerCase().includes(search.toLowerCase())) return false;
      if (priorityFilter && r.urgency !== priorityFilter) return false;
      if (statusFilter && r.status !== statusFilter) return false;
      return true;
    });
  }, [rfis, search, priorityFilter, statusFilter]);

  const openRfis = filtered.filter((r) => !isRfiClosed(r.status));
  const closedRfis = filtered.filter((r) => isRfiClosed(r.status));

  const openCount = openRfis.length + openBuilder.length;
  const closedCount = closedRfis.length + closedBuilder.length;

  const openDrawer = (id: string) => {
    setSelectedId(id);
    mergeParams({ rfi: id });
  };

  const closeDrawer = () => {
    setSelectedId(null);
    mergeParams({ rfi: null });
  };

  const renderBuilderRfiRows = (docs: ProjectDocumentRow[]) =>
    docs.map((doc) => (
      <tr
        key={doc.id}
        className={`border-b border-slate-100 last:border-0 dark:border-slate-800 ${
          builderReviewDocId === doc.id ? 'bg-cyan-50/50 dark:bg-cyan-950/20' : ''
        }`}
      >
        <td className="px-3 py-2 font-mono text-xs">{resolveRfiDisplayNumber(doc)}</td>
        <td className="max-w-[200px] px-3 py-2">
          <div className="truncate font-medium">{doc.title}</div>
          <div className="text-xs text-slate-500 dark:text-slate-400">Document Builder</div>
        </td>
        <td className="px-3 py-2 text-gray-500">—</td>
        <td className="px-3 py-2 text-gray-500">—</td>
        <td className="whitespace-nowrap px-3 py-2 text-gray-500">{formatBuilderDate(doc.updated_at)}</td>
        <td className="px-3 py-2">
          <FieldRecordStatusBadge status={resolveBuilderWorkflowStatusFromDoc(doc)} />
        </td>
        <td className="px-3 py-2 text-right">
          <BuilderDocumentTableActions
            doc={doc}
            projectId={projectId}
            onPrimary={setBuilderReviewDocId}
          />
        </td>
      </tr>
    ));

  const renderOpenClosedTable = (
    legacyRows: RfiRequest[],
    builderRows: ProjectDocumentRow[],
    empty: string,
  ) => {
    if (legacyRows.length === 0 && builderRows.length === 0) {
      return <p className={`${PLANNER_MUTED} py-2 text-sm`}>{empty}</p>;
    }
    return (
      <div className={PLANNER_TABLE_WRAPPER}>
        <table className={PLANNER_TABLE}>
          <thead className={PLANNER_TABLE_HEAD}>
            <tr>
              <th className="px-3 py-2">RFI #</th>
              <th className="px-3 py-2">Subject</th>
              <th className="px-3 py-2">Priority</th>
              <th className="px-3 py-2">Submitted by</th>
              <th className="px-3 py-2">Date</th>
              <th className="px-3 py-2">Status</th>
              <th className="px-3 py-2" />
            </tr>
          </thead>
          <tbody>
            {legacyRows.map((rfi) => (
              <tr
                key={rfi.id}
                className={`border-b border-slate-100 last:border-0 dark:border-slate-800 ${
                  highlightId === rfi.id ? 'bg-cyan-50/50 dark:bg-cyan-950/20' : ''
                }`}
              >
                <td className="px-3 py-2 font-mono text-xs">{rfi.displayNumber ?? '—'}</td>
                <td className="max-w-[200px] truncate px-3 py-2 font-medium">{rfi.title}</td>
                <td className="px-3 py-2">
                  <TaskPriorityBadge priority={rfi.urgency as 'Low' | 'Normal' | 'High' | 'Urgent'} />
                </td>
                <td className="px-3 py-2">{nameFromMap(nameMap, rfi.submittedBy, '—')}</td>
                <td className="whitespace-nowrap px-3 py-2 text-gray-500">
                  {new Date(rfi.createdAt).toLocaleDateString()}
                </td>
                <td className="px-3 py-2">
                  <FieldRecordStatusBadge status={rfi.status} />
                </td>
                <td className="px-3 py-2 text-right">
                  <ProjectRecordActions
                    primary={{ label: 'View / Respond', onClick: () => openDrawer(rfi.id) }}
                  />
                </td>
              </tr>
            ))}
            {renderBuilderRfiRows(builderRows)}
          </tbody>
        </table>
      </div>
    );
  };

  return (
    <>
      <PanelActionRow
        action={
          <Button
            variant="accent"
            size="sm"
            onClick={() =>
              navigate(
                contractBuilderToolHref(projectId, undefined, {
                  packKey: 'GENERIC_RFI',
                  documentType: 'rfi',
                }),
              )
            }
          >
            New RFI
          </Button>
        }
      />

      <div className="mb-4 flex flex-wrap gap-2">
        <input
          type="search"
          placeholder="Search subject…"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="min-w-[160px] flex-1 rounded-lg border border-slate-300 px-3 py-2 text-sm dark:border-slate-600 dark:bg-slate-800"
        />
        <select
          value={priorityFilter}
          onChange={(e) => setPriorityFilter(e.target.value)}
          className="rounded-lg border border-slate-300 px-3 py-2 text-sm dark:border-slate-600 dark:bg-slate-800"
        >
          <option value="">All priorities</option>
          {RFI_PRIORITIES.map((p) => (
            <option key={p} value={p}>
              {p}
            </option>
          ))}
        </select>
        <select
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
          className="rounded-lg border border-slate-300 px-3 py-2 text-sm dark:border-slate-600 dark:bg-slate-800"
        >
          <option value="">All statuses</option>
          <option value="Open">Open</option>
          <option value="Pending Response">Pending Response</option>
          <option value="Need More Information">Need More Information</option>
          <option value="Answered">Answered</option>
          <option value="Closed">Closed</option>
          <option value="Rejected">Rejected</option>
          {RFI_WORKFLOW_STATUSES.map((s) => (
            <option key={`wf-${s}`} value={s}>
              {s} (builder)
            </option>
          ))}
        </select>
      </div>

      <section className="mb-6">
        <h3 className="mb-2 text-xs font-semibold uppercase tracking-wide text-gray-500">
          Open RFIs ({openCount})
        </h3>
        {renderOpenClosedTable(openRfis, openBuilder, 'No open RFIs.')}
      </section>

      <section className="mb-6">
        <h3 className="mb-2 text-xs font-semibold uppercase tracking-wide text-gray-500">
          Closed RFIs ({closedCount})
        </h3>
        {renderOpenClosedTable(closedRfis, closedBuilder, 'No closed RFIs.')}
      </section>

      <section className="mt-8 border-t border-slate-200 pt-6 dark:border-slate-700">
        <h3 className="mb-2 text-xs font-semibold uppercase tracking-wide text-gray-500">
          RFI document drafts ({draftBuilder.length})
        </h3>
        {draftBuilder.length === 0 ? (
          <p className={`${PLANNER_MUTED} py-2 text-sm`}>
            No RFI documents in Draft workflow status. Use New RFI to create one.
          </p>
        ) : (
          <div className={PLANNER_TABLE_WRAPPER}>
            <table className={PLANNER_TABLE}>
              <thead className={PLANNER_TABLE_HEAD}>
                <tr>
                  <th className="px-4 py-3 font-semibold">Updated</th>
                  <th className="px-4 py-3 font-semibold">Title</th>
                  <th className="px-4 py-3 font-semibold">Number / Status</th>
                  <th className="px-4 py-3 font-semibold text-right">Actions</th>
                </tr>
              </thead>
              <tbody>
                {draftBuilder.map((doc) => (
                  <PlannerBuilderDocumentRow
                    key={doc.id}
                    doc={doc}
                    projectId={projectId}
                    onDeleted={() => {
                      setDeleteConfirmDocId(null);
                      onReload();
                    }}
                    onOpenDrawer={setBuilderReviewDocId}
                    deleteConfirm={{
                      deleteConfirmActive: deleteConfirmDocId === doc.id,
                      onDeleteRequest: () => setDeleteConfirmDocId(doc.id),
                      onDeleteCancel: () => setDeleteConfirmDocId(null),
                    }}
                  />
                ))}
              </tbody>
            </table>
          </div>
        )}
      </section>

      <ProjectDocumentDrawer
        documentId={builderReviewDocId}
        projectId={projectId}
        onClose={() => setBuilderReviewDocId(null)}
        onSaved={() => {
          onReload();
          onProjectReload();
        }}
      />

      {userId && (
        <RfiDetailDrawer
          rfiId={selectedId}
          userId={userId}
          isOwner={isOwner}
          onClose={closeDrawer}
          onUpdated={() => {
            onReload();
            onProjectReload();
          }}
        />
      )}

      <DocumentsPanelFootnote />
    </>
  );
}

import React, { useEffect, useRef, useState } from 'react';
import { Loader2, AlertTriangle, CheckCircle2, Truck } from 'lucide-react';
import Input from '../../ui/Input';
import Card from '../../ui/Card';
import ReadyMixDelivery from '../../calculations/ReadyMixDelivery';
import DeliveryClock from '../DeliveryClock';
import PlannerStepLocationsCard from '../PlannerStepLocationsCard';
import type { PourPlannerContext } from '../../../hooks/usePourPlannerState';
import { getMapboxTravelTime } from '../../../services/mapboxTravelService';
import {
  batchPlantDisplayLine,
  jobsiteDisplayAddress,
  plannerTravelCoords,
} from '../../../utils/addressForm';

interface StepProps {
  planner: PourPlannerContext;
}

export const StepDeliveryLogistics: React.FC<StepProps> = ({ planner }) => {
  const {
    form,
    setField,
    volume,
    preferences,
    deliveryWindow,
    production,
    plannedTruckCount,
    suggestedTruckTypeId,
  } = planner;

  const [routeLoading, setRouteLoading] = useState(false);
  const [routeError, setRouteError] = useState<string | null>(null);
  const lastFetchedRef = useRef('');

  const plantAddress = batchPlantDisplayLine(form);
  const jobsiteAddress = jobsiteDisplayAddress(form);
  const travelCoords = plannerTravelCoords(form);
  const canCalculateRoute = plantAddress.length > 0 && jobsiteAddress.length > 0;
  const hasRouteData =
    Boolean(form.travelTimeMinutes && form.travelDistance) &&
    !routeError &&
    !routeLoading;

  const spacingRecommended = Math.round(production.truckSpacingMinutes);
  const multiTruck = plannedTruckCount > 1;

  useEffect(() => {
    if (!canCalculateRoute) {
      lastFetchedRef.current = '';
      return;
    }

    const key = [
      plantAddress,
      jobsiteAddress,
      travelCoords.plant?.lat,
      travelCoords.plant?.lng,
      travelCoords.jobsite?.lat,
      travelCoords.jobsite?.lng,
    ].join('|');
    if (key === lastFetchedRef.current) return;

    let cancelled = false;

    (async () => {
      const hasExistingData = Boolean(form.travelTimeMinutes && form.travelDistance);
      if (!hasExistingData) {
        setRouteLoading(true);
      }
      setRouteError(null);

      try {
        const result = await getMapboxTravelTime(plantAddress, jobsiteAddress, {
          plant: travelCoords.plant
            ? {
                latitude: travelCoords.plant.lat,
                longitude: travelCoords.plant.lng,
              }
            : undefined,
          jobsite: travelCoords.jobsite
            ? {
                latitude: travelCoords.jobsite.lat,
                longitude: travelCoords.jobsite.lng,
              }
            : undefined,
        });
        if (cancelled) return;

        lastFetchedRef.current = key;
        setField('travelDistance', String(result.distanceMiles));
        setField('travelTimeMinutes', String(result.travelMinutes));
        if (result.avgSpeedMph > 0) {
          setField('truckSpeed', String(result.avgSpeedMph));
        }
      } catch (err) {
        if (cancelled) return;
        setRouteError(
          err instanceof Error ? err.message : 'Could not calculate route.',
        );
      } finally {
        if (!cancelled) setRouteLoading(false);
      }
    })();

    return () => {
      cancelled = true;
    };
  }, [
    canCalculateRoute,
    plantAddress,
    jobsiteAddress,
    travelCoords.plant?.lat,
    travelCoords.plant?.lng,
    travelCoords.jobsite?.lat,
    travelCoords.jobsite?.lng,
    setField,
    form.travelTimeMinutes,
    form.travelDistance,
  ]);

  return (
    <div className="space-y-6">
      <section>
        <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-1">
          Plant → jobsite
        </h3>
        <p className="text-sm text-gray-600 dark:text-gray-400 mb-4">
          Travel time uses your verified Step 1 map locations when available. Adjust
          buffers and onsite wait against the ASTM C94 discharge window.
        </p>

        <PlannerStepLocationsCard form={form} className="mb-4" />

        {routeLoading && (
          <div className="mb-4 flex items-center gap-2 text-sm text-gray-600 dark:text-gray-300">
            <Loader2 className="h-4 w-4 animate-spin text-blue-600" />
            Calculating traffic-aware route…
          </div>
        )}

        {!canCalculateRoute && !routeLoading && (
          <p className="mb-4 text-xs text-gray-500 dark:text-gray-400">
            Complete Step 1 (verify jobsite and set batch plant) to calculate travel time.
          </p>
        )}

        {routeError && (
          <div className="mb-4 p-3 rounded-md bg-red-50 dark:bg-red-900/30 text-red-800 dark:text-red-200 text-sm flex gap-2">
            <AlertTriangle className="h-4 w-4 shrink-0 mt-0.5" />
            {routeError}
          </div>
        )}

        {hasRouteData && !routeLoading && (
          <div className="mb-4 p-3 rounded-md bg-green-50 dark:bg-green-900/25 text-green-800 dark:text-green-200 text-sm flex gap-2">
            <CheckCircle2 className="h-4 w-4 shrink-0 mt-0.5" />
            <span>
              Route: {form.travelDistance} mi · {form.travelTimeMinutes} min drive
              {form.truckSpeed ? ` · avg ${form.truckSpeed} mph` : ''}
            </span>
          </div>
        )}

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          <Input
            label="Travel distance (mi)"
            type="number"
            min="0"
            step="0.1"
            value={form.travelDistance}
            onChange={(e) => setField('travelDistance', e.target.value)}
          />
          <Input
            label="Travel time (min)"
            type="number"
            min="0"
            value={form.travelTimeMinutes}
            onChange={(e) => setField('travelTimeMinutes', e.target.value)}
          />
          <Input
            label="Avg truck speed (mph)"
            type="number"
            min="0"
            value={form.truckSpeed}
            onChange={(e) => setField('truckSpeed', e.target.value)}
          />
          <Input
            label="Traffic buffer (min)"
            type="number"
            min="0"
            value={form.trafficBufferMinutes}
            onChange={(e) => setField('trafficBufferMinutes', e.target.value)}
          />
          <Input
            label="Site wait (min)"
            type="number"
            min="0"
            value={form.siteWaitMinutes}
            onChange={(e) => setField('siteWaitMinutes', e.target.value)}
          />
          <Input
            label="Washout delay (min)"
            type="number"
            min="0"
            value={form.washoutDelayMinutes}
            onChange={(e) => setField('washoutDelayMinutes', e.target.value)}
          />
        </div>

        <div className="mt-6">
          <DeliveryClock
            analysis={deliveryWindow}
            drumRpm={form.drumRpm}
          />
        </div>
      </section>

      <section>
        <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4 flex items-center gap-2">
          <Truck className="h-5 w-5" />
          Truck schedule
        </h3>
        <ReadyMixDelivery
          volume={volume}
          volumeUnit={preferences.volumeUnit}
          defaultTruckTypeId={suggestedTruckTypeId}
        />

        <Card className="p-4 mt-4 bg-gray-50 dark:bg-gray-800/50">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <Input
              label="Truck capacity (yd³)"
              type="number"
              min="0"
              value={form.truckCapacityYd}
              onChange={(e) => setField('truckCapacityYd', e.target.value)}
            />
            <Input
              label="Number of trucks"
              type="number"
              min="1"
              value={form.numberOfTrucks}
              onChange={(e) => setField('numberOfTrucks', e.target.value)}
              helperText={
                plannedTruckCount > 0
                  ? `Recommended: ${plannedTruckCount} for this volume`
                  : undefined
              }
            />
            <Input
              label="Truck spacing interval (min)"
              type="number"
              min="0"
              value={form.truckSpacingMinutes}
              onChange={(e) => setField('truckSpacingMinutes', e.target.value)}
              disabled={!multiTruck}
              placeholder={multiTruck ? String(spacingRecommended) : 'N/A'}
              helperText={
                multiTruck
                  ? `Recommended: ~${spacingRecommended} min between arrivals (per-truck discharge time)`
                  : 'Not used for a single-truck placement'
              }
            />
            <Input
              label="Drum RPM"
              type="number"
              min="0"
              step="0.5"
              value={form.drumRpm}
              onChange={(e) => setField('drumRpm', e.target.value)}
            />
          </div>
        </Card>
      </section>
    </div>
  );
};

export default StepDeliveryLogistics;

import React, { useEffect, useState } from 'react';
import { AlertTriangle, CheckCircle2, Factory, Loader2, MapPin } from 'lucide-react';
import Input from '../../ui/Input';
import Select from '../../ui/Select';
import Button from '../../ui/Button';
import USAddressFields from '../../address/USAddressFields';
import type { PourPlannerContext } from '../../../hooks/usePourPlannerState';
import { findBatchPlant, BatchPlantNotFoundError } from '../../../services/batchPlantService';
import { lookupBatchPlantContact } from '../../../services/batchPlantContactService';
import { hasSavedBatchPlantContact } from '../../../utils/projectLocation';
import { getMapboxTravelTime } from '../../../services/mapboxTravelService';
import { verifyJobsiteAddress } from '../../../services/geocodeService';
import type { BatchPlantResult } from '../../../services/batchPlantService';
import type { GeocodedAddressResult } from '../../../services/geocodeService';
import {
  formatUSAddress,
  isUSAddressGeocodable,
  mergeVerifiedJobsiteAddress,
  normalizeUSAddressInput,
  parseLegacyUSAddress,
  validateUSAddress,
} from '../../../types/address';
import {
  applyUSAddressToPourPlanner,
  jobsiteFromPourPlannerForm,
} from '../../../utils/addressForm';
import {
  hasSavedBatchPlant,
  getSavedPlacementOrder,
} from '../../../utils/projectLocation';

interface StepProps {
  planner: PourPlannerContext;
}

const CUSTOM_PROJECT_VALUE = '__custom__';

function applyJobsiteFields(
  setField: PourPlannerContext['setField'],
  patch: ReturnType<typeof applyUSAddressToPourPlanner>,
) {
  (Object.entries(patch) as [keyof typeof patch, string][]).forEach(([key, value]) => {
    if (value !== undefined) setField(key as keyof PourPlannerContext['form'], value);
  });
}

export const StepProjectOverview: React.FC<StepProps> = ({ planner }) => {
  const { form, setField, projects, preferences, calculation } = planner;
  const selectedProject = projects.find((p) => p.id === form.projectId);
  const projectCalculations = selectedProject?.calculations ?? [];
  const usingSavedProject = Boolean(form.projectId);

  const [findPlantLoading, setFindPlantLoading] = useState(false);
  const [findPlantError, setFindPlantError] = useState<string | null>(null);
  const [routeError, setRouteError] = useState<string | null>(null);
  const [foundPlant, setFoundPlant] = useState<BatchPlantResult | null>(null);
  const [travelLoading, setTravelLoading] = useState(false);
  const [verifyLoading, setVerifyLoading] = useState(false);
  const [verifyError, setVerifyError] = useState<string | null>(null);
  const [verifiedJobsite, setVerifiedJobsite] = useState<GeocodedAddressResult | null>(null);

  const jobsiteAddr = jobsiteFromPourPlannerForm(form);
  const hasJobsiteAddress = isUSAddressGeocodable(jobsiteAddr);
  const jobsiteReady = Boolean(verifiedJobsite);
  const projectHasAddress = Boolean(
    selectedProject?.jobsiteAddress &&
      isUSAddressGeocodable(selectedProject.jobsiteAddress),
  );

  useEffect(() => {
    if (form.jobsiteCity || form.jobsiteState) return;
    if (!form.jobsiteAddress.trim()) return;
    const parsed = parseLegacyUSAddress(form.jobsiteAddress);
    if (parsed.city || parsed.state || parsed.street) {
      applyJobsiteFields(setField, applyUSAddressToPourPlanner({}, parsed));
    }
  }, []);

  const volumeLabel =
    preferences.volumeUnit === 'cubic_yards'
      ? 'yd³'
      : preferences.volumeUnit === 'cubic_feet'
        ? 'ft³'
        : 'm³';

  const clearLocationState = () => {
    setFoundPlant(null);
    setFindPlantError(null);
    setRouteError(null);
    setVerifiedJobsite(null);
    setVerifyError(null);
    setField('jobsiteAddress', '');
    setField('jobsiteLatitude', '');
    setField('jobsiteLongitude', '');
    setField('batchPlantName', '');
    setField('batchPlantLatitude', '');
    setField('batchPlantLongitude', '');
  };

  const handleJobsiteAddressChange = (next: typeof jobsiteAddr) => {
    applyJobsiteFields(setField, applyUSAddressToPourPlanner({}, next));
    clearLocationState();
  };

  const handleUseProjectAddress = () => {
    if (!selectedProject?.jobsiteAddress) return;
    applyJobsiteFields(
      setField,
      applyUSAddressToPourPlanner({}, selectedProject.jobsiteAddress),
    );
    clearLocationState();
  };

  const handleProjectChange = (value: string) => {
    if (value === '') {
      setField('projectId', '');
      setField('calculationId', '');
      setField('projectName', '');
      return;
    }

    if (value === CUSTOM_PROJECT_VALUE) {
      setField('projectId', '');
      setField('calculationId', '');
      return;
    }

    const project = projects.find((p) => p.id === value);
    setField('projectId', value);
    setField('calculationId', '');
    if (project) {
      setField('projectName', project.name);
      if (project.jobsiteAddress && isUSAddressGeocodable(project.jobsiteAddress)) {
        applyJobsiteFields(
          setField,
          applyUSAddressToPourPlanner({}, project.jobsiteAddress),
        );
        clearLocationState();
      }
    }
  };

  const projectSelectValue = form.projectId
    ? form.projectId
    : form.projectName.trim()
      ? CUSTOM_PROJECT_VALUE
      : '';

  const resolveVerifiedJobsite = async (): Promise<GeocodedAddressResult> => {
    const normalized = normalizeUSAddressInput(jobsiteAddr);
    if (
      normalized.street !== jobsiteAddr.street ||
      normalized.city !== jobsiteAddr.city ||
      normalized.state !== jobsiteAddr.state ||
      normalized.zip !== jobsiteAddr.zip
    ) {
      applyJobsiteFields(setField, applyUSAddressToPourPlanner({}, normalized));
    }

    const validation = validateUSAddress(normalized, {
      requireStreet: true,
      requireZip: false,
    });
    if (!validation.ok) {
      throw new Error(validation.errors.join(' '));
    }
    return verifyJobsiteAddress(normalized);
  };

  const handleVerifyJobsite = async () => {
    if (!hasJobsiteAddress) return;

    setVerifyLoading(true);
    setVerifyError(null);
    setVerifiedJobsite(null);
    setFoundPlant(null);
    setFindPlantError(null);
    setRouteError(null);

    try {
      const verified = await resolveVerifiedJobsite();
      const normalized = normalizeUSAddressInput(jobsiteFromPourPlannerForm(form));
      const merged =
        verified.addressParts ??
        mergeVerifiedJobsiteAddress(normalized, verified.formattedAddress);
      setVerifiedJobsite(verified);
      applyJobsiteFields(setField, applyUSAddressToPourPlanner({}, merged));
      setField('jobsiteAddress', formatUSAddress(merged));
      setField('jobsiteLatitude', String(verified.latitude));
      setField('jobsiteLongitude', String(verified.longitude));
    } catch (err) {
      setVerifyError(
        err instanceof Error ? err.message : 'Could not verify jobsite address.',
      );
    } finally {
      setVerifyLoading(false);
    }
  };

  const handleFindBatchPlant = async () => {
    if (!hasJobsiteAddress) return;

    if (hasSavedBatchPlant(selectedProject) && form.batchPlantName.trim()) {
      setFindPlantError(null);
      const saved = getSavedPlacementOrder(selectedProject);
      if (saved?.batchPlantName) {
        setField('batchPlantName', saved.batchPlantName);
      }
      if (saved?.batchPlantAddress) {
        setField('batchPlantAddress', saved.batchPlantAddress);
      }
      return;
    }

    setFindPlantLoading(true);
    setFindPlantError(null);
    setRouteError(null);
    setFoundPlant(null);

    try {
      let jobsite = verifiedJobsite;
      if (!jobsite) {
        jobsite = await resolveVerifiedJobsite();
        const normalized = normalizeUSAddressInput(jobsiteFromPourPlannerForm(form));
        const merged =
          jobsite.addressParts ??
          mergeVerifiedJobsiteAddress(normalized, jobsite.formattedAddress);
        setVerifiedJobsite(jobsite);
        applyJobsiteFields(setField, applyUSAddressToPourPlanner({}, merged));
        setField('jobsiteAddress', formatUSAddress(merged));
        setField('jobsiteLatitude', String(jobsite.latitude));
        setField('jobsiteLongitude', String(jobsite.longitude));
      }

      const plant = await findBatchPlant(jobsite.formattedAddress, {
        latitude: jobsite.latitude,
        longitude: jobsite.longitude,
      });
      setFoundPlant(plant);
      setField('batchPlantName', plant.plantName);
      setField('batchPlantAddress', plant.formattedAddress);
      setField('batchPlantLatitude', String(plant.latitude));
      setField('batchPlantLongitude', String(plant.longitude));
      if (plant.distanceMiles > 0) {
        setField('travelDistance', String(plant.distanceMiles));
      }
      if (plant.driveMinutes != null && plant.driveMinutes > 0) {
        setField('travelTimeMinutes', String(plant.driveMinutes));
      }

      setTravelLoading(true);
      try {
        const route = await getMapboxTravelTime(
          plant.formattedAddress,
          jobsite.formattedAddress,
          {
            plant: { latitude: plant.latitude, longitude: plant.longitude },
            jobsite: { latitude: jobsite.latitude, longitude: jobsite.longitude },
          },
        );
        setField('travelDistance', String(route.distanceMiles));
        setField('travelTimeMinutes', String(route.travelMinutes));
        if (route.avgSpeedMph > 0) {
          setField('truckSpeed', String(route.avgSpeedMph));
        }

        if (!hasSavedBatchPlantContact(selectedProject)) {
          try {
            const contact = await lookupBatchPlantContact({
              plantName: plant.plantName,
              plantAddress: plant.formattedAddress,
              latitude: plant.latitude,
              longitude: plant.longitude,
            });
            if (contact.phone) setField('batchPlantPhone', contact.phone);
            if (contact.email) setField('batchPlantEmail', contact.email);
            if (contact.dispatchContact) {
              setField('batchPlantDispatchContact', contact.dispatchContact);
            }
            if (contact.website) setField('batchPlantWebsite', contact.website);
            setField('batchPlantContactSource', 'ai');
          } catch {
            /* contact lookup is optional; user can enter manually on call sheet */
          }
        }
      } catch (routeErr) {
        setRouteError(
          routeErr instanceof Error
            ? routeErr.message
            : 'Could not calculate route.',
        );
      } finally {
        setTravelLoading(false);
      }
    } catch (err) {
      if (err instanceof BatchPlantNotFoundError) {
        setFindPlantError(err.message);
      } else {
        setFindPlantError(
          err instanceof Error ? err.message : 'Could not find a nearby batch plant.',
        );
      }
    } finally {
      setFindPlantLoading(false);
    }
  };

  const isSearching = findPlantLoading || travelLoading;
  const formattedPreview = formatUSAddress(jobsiteAddr);

  return (
    <div>
      <section>
        <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-1">
          Project overview
        </h3>
        <p className="text-sm text-gray-600 dark:text-gray-400 mb-4">
          Choose a saved project or enter a placement name, verify the jobsite location, then find or
          enter the batch plant address.
        </p>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          {projects.length > 0 ? (
            <>
              <Select
                label="Project"
                options={[
                  { value: '', label: 'Select a project' },
                  ...projects.map((p) => ({ value: p.id, label: p.name })),
                  { value: CUSTOM_PROJECT_VALUE, label: 'Custom placement (manual name)' },
                ]}
                value={projectSelectValue}
                onChange={handleProjectChange}
              />
              {!usingSavedProject && (
                <Input
                  label="Project name"
                  value={form.projectName}
                  onChange={(e) => setField('projectName', e.target.value)}
                  placeholder="e.g. Main St slab placement"
                />
              )}
            </>
          ) : (
            <Input
              label="Project name"
              value={form.projectName}
              onChange={(e) => setField('projectName', e.target.value)}
              placeholder="e.g. Main St slab placement"
            />
          )}

          {usingSavedProject && projectCalculations.length > 0 && (
            <Select
              label="Calculation"
              options={[
                { value: '', label: 'Select a calculation…' },
                ...projectCalculations.map((c) => ({
                  value: c.id,
                  label: `${c.type.replace(/_/g, ' ')} — ${c.result.volume.toFixed(2)} ${volumeLabel}`,
                })),
              ]}
              value={form.calculationId}
              onChange={(v) => setField('calculationId', v)}
            />
          )}

          {!calculation && (
            <Input
              label={`Volume (${volumeLabel})`}
              type="number"
              min="0"
              step="0.01"
              value={form.manualVolume}
              onChange={(e) => setField('manualVolume', e.target.value)}
              placeholder="e.g. 40"
              className={
                usingSavedProject && projectCalculations.length > 0
                  ? 'sm:col-span-2'
                  : undefined
              }
            />
          )}

          <Input
            label="Placement start time"
            type="time"
            value={form.pourStartTime}
            onChange={(e) => setField('pourStartTime', e.target.value)}
          />

          <div className="sm:col-span-2">
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-2 mb-2">
              <label className="block text-sm font-medium text-slate-700 dark:text-gray-300">
                Jobsite address
              </label>
              {usingSavedProject && projectHasAddress && (
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  onClick={handleUseProjectAddress}
                  className="whitespace-nowrap self-start sm:self-auto"
                >
                  Use project address
                </Button>
              )}
            </div>
            <USAddressFields
              value={jobsiteAddr}
              onChange={handleJobsiteAddressChange}
              idPrefix="pour-jobsite"
            />
            {formattedPreview && (
              <p className="mt-2 text-xs text-gray-500 dark:text-gray-400">
                Formatted: {formattedPreview}
              </p>
            )}
            <div className="mt-3 flex flex-col sm:flex-row gap-2">
              <Button
                type="button"
                variant="outline"
                onClick={handleVerifyJobsite}
                disabled={!hasJobsiteAddress || verifyLoading || isSearching}
                className="whitespace-nowrap"
                icon={
                  verifyLoading ? (
                    <Loader2 className="h-4 w-4 animate-spin" />
                  ) : (
                    <MapPin className="h-4 w-4" />
                  )
                }
              >
                {verifyLoading ? 'Verifying…' : 'Verify location'}
              </Button>
            </div>
            <p className="mt-1 text-xs text-gray-500 dark:text-gray-400">
              Street, city, and state/territory are required for verify and batch plant search. ZIP
              is optional but improves accuracy. US and territories only.
            </p>
            {verifyError && (
              <div className="mt-2 p-3 rounded-md bg-red-50 dark:bg-red-900/30 text-red-800 dark:text-red-200 text-sm flex gap-2">
                <AlertTriangle className="h-4 w-4 shrink-0 mt-0.5" />
                {verifyError}
              </div>
            )}
            {jobsiteReady && verifiedJobsite && (
              <div className="mt-2 p-3 rounded-md bg-blue-50 dark:bg-blue-900/25 text-blue-900 dark:text-blue-100 text-sm flex gap-2">
                <CheckCircle2 className="h-4 w-4 shrink-0 mt-0.5" />
                <span>Verified: {verifiedJobsite.formattedAddress}</span>
              </div>
            )}
          </div>

          <div className="sm:col-span-2">
            <label className="block text-sm font-medium mb-1 text-slate-700 dark:text-gray-300">
              Batch plant address
            </label>
            <div className="flex flex-col sm:flex-row gap-2">
              <div className="flex-1">
                <Input
                  value={form.batchPlantAddress}
                  onChange={(e) => {
                    setField('batchPlantAddress', e.target.value);
                    setField('batchPlantName', '');
                    setField('batchPlantLatitude', '');
                    setField('batchPlantLongitude', '');
                    setFoundPlant(null);
                    setFindPlantError(null);
                    setRouteError(null);
                  }}
                  placeholder="Ready-mix plant (from search or manual entry)"
                  fullWidth
                />
              </div>
              <Button
                type="button"
                variant="outline"
                onClick={handleFindBatchPlant}
                disabled={!hasJobsiteAddress || isSearching || verifyLoading}
                className="sm:self-end whitespace-nowrap"
                icon={
                  isSearching ? (
                    <Loader2 className="h-4 w-4 animate-spin" />
                  ) : (
                    <Factory className="h-4 w-4" />
                  )
                }
              >
                {findPlantLoading
                  ? 'Searching…'
                  : travelLoading
                    ? 'Calculating route…'
                    : 'Find Batch Plant'}
              </Button>
            </div>
            {!hasJobsiteAddress && (
              <p className="mt-1 text-xs text-gray-500 dark:text-gray-400">
                Complete and verify the jobsite address to search for nearby batch plants.
              </p>
            )}
            {findPlantError && (
              <div className="mt-2 p-3 rounded-md bg-amber-50 dark:bg-amber-900/25 text-amber-900 dark:text-amber-100 text-sm flex gap-2">
                <AlertTriangle className="h-4 w-4 shrink-0 mt-0.5" />
                {findPlantError}
              </div>
            )}
            {routeError && (
              <div className="mt-2 p-3 rounded-md bg-amber-50 dark:bg-amber-900/25 text-amber-900 dark:text-amber-100 text-sm flex gap-2">
                <AlertTriangle className="h-4 w-4 shrink-0 mt-0.5" />
                Plant found, but route calculation failed: {routeError}
              </div>
            )}
            {foundPlant && (
              <div className="mt-2 p-3 rounded-md bg-green-50 dark:bg-green-900/25 text-green-800 dark:text-green-200 text-sm flex gap-2">
                <CheckCircle2 className="h-4 w-4 shrink-0 mt-0.5" />
                <span>
                  Found {foundPlant.plantName} (
                  {form.travelDistance || String(foundPlant.distanceMiles)} mi drive,{' '}
                  {foundPlant.confidence} confidence)
                  {form.travelTimeMinutes
                    ? ` · ${form.travelTimeMinutes} min`
                    : foundPlant.driveMinutes
                      ? ` · ${foundPlant.driveMinutes} min`
                      : ''}
                </span>
              </div>
            )}
          </div>

          <Select
            label="Placement method"
            options={[
              { value: '', label: 'Select method…' },
              { value: 'chute', label: 'Chute' },
              { value: 'pump', label: 'Pump truck' },
              { value: 'conveyor', label: 'Conveyor' },
              { value: 'buggy', label: 'Buggy' },
              { value: 'bucket', label: 'Crane bucket' },
            ]}
            value={form.placementMethod}
            onChange={(v) =>
              setField('placementMethod', v as typeof form.placementMethod)
            }
          />
        </div>
      </section>
    </div>
  );
};

export default StepProjectOverview;

import React, { useMemo } from 'react';
import { motion } from 'framer-motion';
import { format, parseISO } from 'date-fns';
import { Folder, Clock, Trash2, AlertTriangle, CheckCircle2, ArrowRight } from 'lucide-react';
import Card from '../ui/Card';
import Button from '../ui/Button';
import type { Project } from '../../types';
import { soundService } from '../../services/soundService';
import { hapticService } from '../../services/hapticService';
import {
  resolveProjectWorkflow,
  PROJECT_LIFECYCLE_LABELS,
  normalizeWorkflowStageForDisplay,
  getProjectCardPresentation,
} from '../../utils/projectWorkflow';
import {
  getQcBreakStatus,
  type ProjectFolder,
} from '../../utils/projectFolders';
import {
  PLACEMENT_ORDER_STATUS_LABELS,
  type PlacementOrderStatus,
} from '../../types/placementOrder';
import { useTrackedProposals } from '../../hooks/useTrackedProposals';
import type { TrackedProposalRow } from '../../types/proposalTracking';

interface ProjectCardProps {
  project: Project;
  folder?: ProjectFolder;
  onClick: () => void;
  onDelete: () => void;
}

function breakStatusLabel(complete: boolean, overdue?: boolean): string {
  if (complete) return 'Complete';
  if (overdue) return 'Overdue';
  return 'Pending';
}

function parsePourDate(iso?: string): Date | null {
  if (!iso) return null;
  const d = new Date(iso);
  return Number.isNaN(d.getTime()) ? null : d;
}

const ProjectCard: React.FC<ProjectCardProps> = ({
  project,
  folder = 'active',
  onClick,
  onDelete,
}) => {
  const p = project as any;
  const { proposals } = useTrackedProposals();
  const stopCardOpen = (e: React.SyntheticEvent) => {
    e.preventDefault();
    e.stopPropagation();
  };
  const handleCardClick = async () => {
    await hapticService.selection();
    onClick();
  };

  const formattedDate = (() => {
    try {
      if (!project.updatedAt) return '—';
      const date = parseISO(project.updatedAt);
      if (isNaN(date.getTime())) {
        console.error('Invalid date:', project.updatedAt);
        return '—';
      }
      return format(date, 'MMM d, yyyy');
    } catch (error) {
      console.error('Error formatting date:', error);
      return '—';
    }
  })();

  const matchedProposal: TrackedProposalRow | undefined = useMemo(() => {
    const direct = proposals.find((proposal) => proposal.project_id === project.id);
    if (direct) return direct;
    const name = project.name?.trim() ?? '';
    if (!name) return undefined;
    const lower = name.toLowerCase();
    return proposals.find(
      (proposal) =>
        proposal.data?.projectTitle === name ||
        proposal.title?.toLowerCase().includes(lower),
    );
  }, [proposals, project.id, project.name]);

  const workflow = resolveProjectWorkflow(project as any, {
    hasProposalDraft: Boolean(matchedProposal),
    proposalStatus: matchedProposal?.status,
    windRisk: 'unknown',
    heatRisk: 'unknown',
    readinessScore: 0,
    now: new Date(),
  });

  const displayStage = normalizeWorkflowStageForDisplay(workflow.stage);
  const pourDate = parsePourDate(p.pourDate);
  const hasPourDate = Boolean(p.pourDate);
  const folderCtx = {
    hasProposalDraft: Boolean(matchedProposal),
    proposalStatus: matchedProposal?.status,
  };

  const qcStatus = getQcBreakStatus(project, workflow.stage, folderCtx);

  const presentation = getProjectCardPresentation(
    workflow.stage,
    workflow.nextAction.label,
    hasPourDate,
    pourDate,
  );

  const badgeLabel =
    folder === 'qc_closeout'
      ? 'QC Closeout'
      : folder === 'archived'
        ? 'Archived'
        : presentation.priorityLabel;

  const badgeClass =
    folder === 'qc_closeout'
      ? 'bg-violet-500/15 text-violet-800 border-violet-500/40 dark:text-violet-200'
      : folder === 'archived'
        ? 'bg-slate-600/20 text-slate-700 border-slate-500/50 dark:text-slate-200'
        : presentation.priorityBadgeClass;

  const ringClass =
    folder === 'qc_closeout'
      ? 'ring-1 ring-violet-500/35'
      : presentation.priorityRingClass;

  const nextActionLabel =
    folder === 'archived'
      ? 'View project'
      : folder === 'qc_closeout'
        ? qcStatus.qcComplete
          ? 'View project'
          : `Enter ${qcStatus.nextDueLabel}`
        : presentation.nextActionLabel;

  const showPlacementOrder =
    folder === 'active' && !presentation.hidePlacementOrder;

  const volumeYd = (p.calculations ?? []).reduce(
    (s: number, c: any) => s + ((c.result?.volume as number) ?? 0),
    0,
  );
  const psiFromCalc =
    p.calculations?.[0]?.psi ??
    p.calculations?.[0]?.mixDesign?.psi ??
    '';
  const psi = psiFromCalc ? `${psiFromCalc} PSI` : 'Mix: —';
  const plant = p.placementOrder?.batchPlantName?.trim()
    ? p.placementOrder.batchPlantName
    : 'Plant: —';
  const orderStatusKey = (p.placementOrder?.status ?? 'draft') as PlacementOrderStatus;
  const orderStatusLabel = PLACEMENT_ORDER_STATUS_LABELS[orderStatusKey];

  return (
    <motion.div
      whileHover={{ y: -5 }}
      whileTap={{ scale: 0.98 }}
    >
      <Card 
        className={`cursor-pointer h-full ${ringClass}`}
        shadow="md"
      >
        <div className="p-5">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center min-w-0" onClick={handleCardClick}>
              <div className="p-2 bg-blue-100 dark:bg-blue-900 rounded-lg">
                <Folder className="h-6 w-6 text-blue-600 dark:text-blue-400" />
              </div>
              <h3 className="ml-3 text-lg font-semibold text-gray-900 dark:text-white truncate">
                {project.name}
              </h3>
            </div>
            <div
              onClick={(e) => {
                e.preventDefault();
                e.stopPropagation();
              }}
              onPointerDownCapture={stopCardOpen}
              onMouseDownCapture={stopCardOpen}
              onTouchStartCapture={stopCardOpen}
            >
              <Button
                variant="ghost"
                size="sm"
                onClick={(e) => {
                  e.preventDefault();
                  e.stopPropagation();
                  soundService.play('trash');
                  onDelete();
                }}
                icon={<Trash2 size={16} />}
                className="text-gray-400 hover:text-red-600 dark:text-gray-500 dark:hover:text-red-400"
              />
            </div>
          </div>

          <div className="flex items-center justify-between gap-2 mb-3" onClick={handleCardClick}>
            <span
              className={`inline-block text-[10px] font-semibold uppercase tracking-wider px-2 py-0.5 rounded border ${badgeClass}`}
            >
              {badgeLabel}
            </span>
            <span className="text-xs text-gray-500 dark:text-gray-400 text-right shrink-0 max-w-[50%] truncate">
              {presentation.cornerDateLabel}
            </span>
          </div>

          <div
            className="rounded-lg border border-gray-200/60 dark:border-gray-700/70 bg-white/40 dark:bg-gray-900/20 p-3 mb-3"
            onClick={handleCardClick}
          >
            <p className="text-[10px] uppercase tracking-wide text-gray-500 dark:text-gray-400">Status</p>
            <p className="text-sm font-semibold text-gray-900 dark:text-white mt-0.5">
              {PROJECT_LIFECYCLE_LABELS[displayStage]}
            </p>

            <p className="text-[10px] uppercase tracking-wide text-gray-500 dark:text-gray-400 mt-2">Next action</p>
            <p className="text-sm font-semibold text-gray-900 dark:text-white mt-0.5 flex items-center gap-2">
              <ArrowRight className="h-4 w-4 text-cyan-500" />
              <span className="truncate">{nextActionLabel}</span>
            </p>
            {showPlacementOrder && (
              <>
                <p className="text-[10px] uppercase tracking-wide text-gray-500 dark:text-gray-400 mt-2">
                  Placement order
                </p>
                <p className="text-xs text-gray-700 dark:text-gray-300 mt-0.5 truncate" title={orderStatusLabel}>
                  {orderStatusLabel}
                </p>
              </>
            )}
            {folder === 'active' &&
              workflow.mixDesign &&
              workflow.mixDesign.totalPlacements > 0 && (
                <p className="text-[11px] text-gray-500 dark:text-gray-400 mt-1">
                  Mix designs: {workflow.mixDesign.approvedCount}/
                  {workflow.mixDesign.totalPlacements} approved
                </p>
              )}
          </div>

          {folder === 'qc_closeout' && (
            <div
              className="rounded-lg border border-violet-500/25 bg-violet-500/5 dark:bg-violet-950/20 p-3 mb-3 space-y-2"
              onClick={handleCardClick}
            >
              <p className="text-[10px] uppercase tracking-wide text-violet-400/90">
                QC closeout
              </p>
              <p className="text-xs text-gray-600 dark:text-gray-300">
                Placed:{' '}
                <span className="font-semibold text-gray-900 dark:text-white">
                  {qcStatus.placedDateLabel}
                </span>
              </p>
              <div className="grid grid-cols-3 gap-2 text-[10px]">
                <div>
                  <p className="text-gray-500 dark:text-gray-400">7-day</p>
                  <p
                    className={`font-semibold ${
                      qcStatus.sevenDayComplete
                        ? 'text-emerald-600 dark:text-emerald-400'
                        : qcStatus.sevenDayOverdue
                          ? 'text-red-600 dark:text-red-400'
                          : 'text-amber-600 dark:text-amber-400'
                    }`}
                  >
                    {breakStatusLabel(qcStatus.sevenDayComplete, qcStatus.sevenDayOverdue)}
                  </p>
                </div>
                <div>
                  <p className="text-gray-500 dark:text-gray-400">14-day</p>
                  <p
                    className={`font-semibold ${
                      qcStatus.fourteenDayComplete
                        ? 'text-emerald-600 dark:text-emerald-400'
                        : qcStatus.fourteenDayOverdue
                          ? 'text-red-600 dark:text-red-400'
                          : 'text-amber-600 dark:text-amber-400'
                    }`}
                  >
                    {breakStatusLabel(
                      qcStatus.fourteenDayComplete,
                      qcStatus.fourteenDayOverdue,
                    )}
                  </p>
                </div>
                <div>
                  <p className="text-gray-500 dark:text-gray-400">28-day</p>
                  <p
                    className={`font-semibold ${
                      qcStatus.twentyEightDayComplete
                        ? 'text-emerald-600 dark:text-emerald-400'
                        : qcStatus.twentyEightDayOverdue
                          ? 'text-red-600 dark:text-red-400'
                          : 'text-amber-600 dark:text-amber-400'
                    }`}
                  >
                    {breakStatusLabel(
                      qcStatus.twentyEightDayComplete,
                      qcStatus.twentyEightDayOverdue,
                    )}
                  </p>
                </div>
              </div>
              <div className="flex items-center justify-between text-xs pt-1 border-t border-violet-500/15">
                <span className="text-gray-500 dark:text-gray-400">
                  Next: <span className="font-medium text-gray-800 dark:text-gray-200">{qcStatus.nextDueLabel}</span>
                </span>
                <span
                  className={
                    qcStatus.isOverdue
                      ? 'font-semibold text-red-600 dark:text-red-400'
                      : 'text-gray-600 dark:text-gray-300'
                  }
                >
                  {qcStatus.daysUntilOrOverdueLabel}
                </span>
              </div>
              <div>
                <div className="flex justify-between text-[10px] text-gray-500 dark:text-gray-400 mb-0.5">
                  <span>QC progress</span>
                  <span>{qcStatus.progressPercent}%</span>
                </div>
                <div className="h-1.5 w-full bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden">
                  <div
                    className="h-1.5 bg-violet-500 rounded-full"
                    style={{ width: `${qcStatus.progressPercent}%` }}
                  />
                </div>
              </div>
            </div>
          )}

          {folder !== 'qc_closeout' && (
            <div className="mb-3" onClick={handleCardClick}>
              <div className="flex items-center justify-between text-xs text-gray-500 dark:text-gray-400 mb-1">
                <span>{folder === 'archived' ? 'Job progress' : 'Progress'}</span>
                <span className="font-semibold text-gray-700 dark:text-gray-200">
                  {folder === 'archived' ? 100 : presentation.progressPct}%
                </span>
              </div>
              <div className="h-2 w-full bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden">
                <div
                  className={`h-2 rounded-full ${
                    folder === 'archived' || workflow.stage === 'closed'
                      ? 'bg-slate-500'
                      : 'bg-gradient-to-r from-emerald-500 to-cyan-500'
                  }`}
                  style={{
                    width: `${folder === 'archived' ? 100 : presentation.progressPct}%`,
                  }}
                />
              </div>
            </div>
          )}

          {folder === 'active' && (
            <div
              className="grid grid-cols-3 gap-2 text-[11px] text-gray-600 dark:text-gray-300"
              onClick={handleCardClick}
            >
              <div className="truncate">{volumeYd > 0 ? `${volumeYd.toFixed(0)} CY` : 'Vol: —'}</div>
              <div className="truncate">{psi}</div>
              <div className="truncate">{plant}</div>
            </div>
          )}

          <div
            className="flex items-center justify-between text-xs text-gray-500 dark:text-gray-400 mt-3"
            onClick={handleCardClick}
          >
            <div className="flex items-center">
              <Clock className="h-4 w-4 mr-1" />
              <span>{formattedDate}</span>
            </div>
            {folder === 'archived' ? (
              <div className="flex items-center gap-1.5">
                <CheckCircle2 className="h-4 w-4 text-slate-400" />
                <span>Archived</span>
              </div>
            ) : folder === 'qc_closeout' ? (
              <div className="flex items-center gap-1.5">
                {qcStatus.isOverdue ? (
                  <AlertTriangle className="h-4 w-4 text-red-500" />
                ) : (
                  <CheckCircle2 className="h-4 w-4 text-violet-400" />
                )}
                <span>{qcStatus.daysUntilOrOverdueLabel}</span>
              </div>
            ) : presentation.scheduleFooterComplete ? (
              <div className="flex items-center gap-1.5">
                <CheckCircle2
                  className={`h-4 w-4 ${
                    workflow.stage === 'closed'
                      ? 'text-slate-400'
                      : 'text-emerald-500'
                  }`}
                />
                <span>{presentation.scheduleFooterLabel}</span>
              </div>
            ) : (
              <div className="flex items-center gap-1.5">
                <AlertTriangle className="h-4 w-4 text-amber-500" />
                <span>{presentation.scheduleFooterLabel}</span>
              </div>
            )}
          </div>
        </div>
      </Card>
    </motion.div>
  );
};

export default ProjectCard;

import React, { useState, useEffect } from 'react';
import { useForm, Controller } from 'react-hook-form';
import { Save, X, Calendar, MapPin, Loader2, CheckCircle2, Sparkles } from 'lucide-react';
import { useAuth } from '../../hooks/useAuth';
import { useProjectStore } from '../../store';
import { generateProjectName } from '../../services/projectNamingService';
import { resolveStateCode } from '../../types/address';
import Button from '../ui/Button';
import Input from '../ui/Input';
import Card from '../ui/Card';
import USAddressFields from '../address/USAddressFields';
import type { USAddress } from '../../types/address';
import type { ProjectClientInfo } from '../../types/projectClient';
import {
  EMPTY_US_ADDRESS,
  copyUSAddress,
  isUSAddressGeocodable,
  mergeVerifiedJobsiteAddress,
  repairJobsiteAddress,
  sanitizeUSAddress,
  validateUSAddress,
} from '../../types/address';
import { verifyJobsiteAddress } from '../../services/geocodeService';
import { EMPTY_PROJECT_CLIENT } from '../../types/projectClient';
import type { ClientPortalAccessInput } from '../../types/clientPortal';
import { formatUSPhoneInput, formatUSPhoneNumber } from '../../utils/phoneFormat';
import {
  fetchClientPortalByProjectId,
  getClientPortalUrl,
} from '../../services/clientPortalService';
import type { ClientPortalRecord } from '../../types/clientPortal';

export interface ProjectFormData {
  name: string;
  description: string;
  pourDate?: string;
  jobsiteAddress: USAddress;
  clientInfo: ProjectClientInfo;
  clientPortalAccess?: ClientPortalAccessInput;
}

interface ProjectFormProps {
  onSubmit: (data: ProjectFormData) => void | Promise<void>;
  onCancel: () => void;
  initialData?: Partial<ProjectFormData>;
  isEditing?: boolean;
  isModal?: boolean;
  submitLabel?: string;
  hidePourDate?: boolean;
  /** Require Mapbox-verified jobsite before create/update (workflow step 1). */
  requireVerifiedAddress?: boolean;
  /** When editing, used to detect an existing client portal. */
  projectId?: string;
}

const defaultJobsite = (): USAddress => ({ ...EMPTY_US_ADDRESS });

const ProjectForm: React.FC<ProjectFormProps> = ({
  onSubmit,
  onCancel,
  initialData,
  isEditing = false,
  isModal = false,
  submitLabel,
  hidePourDate = false,
  requireVerifiedAddress = false,
  projectId,
}) => {
  const [verifyLoading, setVerifyLoading] = useState(false);
  const [verifyError, setVerifyError] = useState<string | null>(null);
  const [verifiedLine, setVerifiedLine] = useState<string | null>(null);
  const [verifiedAddress, setVerifiedAddress] = useState<USAddress | null>(null);
  const [existingPortal, setExistingPortal] = useState<ClientPortalRecord | null>(null);
  const [portalLoading, setPortalLoading] = useState(Boolean(projectId));
  const [nameGenerating, setNameGenerating] = useState(false);
  const [generateError, setGenerateError] = useState<string | null>(null);
  const [generatedNamePreview, setGeneratedNamePreview] = useState<string | null>(null);
  const { user } = useAuth();
  const storeProjects = useProjectStore((s) => s.projects);

  const buildDefaults = (): ProjectFormData => ({
    name: initialData?.name ?? '',
    description: initialData?.description ?? '',
    pourDate: hidePourDate
      ? initialData?.pourDate
      : initialData?.pourDate ?? new Date().toISOString().split('T')[0],
    jobsiteAddress: initialData?.jobsiteAddress
      ? repairJobsiteAddress(initialData.jobsiteAddress)
      : defaultJobsite(),
    clientInfo: {
      ...EMPTY_PROJECT_CLIENT,
      ...initialData?.clientInfo,
      clientPhone: formatUSPhoneNumber(initialData?.clientInfo?.clientPhone),
      clientAddress: initialData?.clientInfo?.clientAddress
        ? repairJobsiteAddress(initialData.clientInfo.clientAddress)
        : { ...EMPTY_US_ADDRESS },
    },
    clientPortalAccess: {
      enabled: false,
      clientName: initialData?.clientInfo?.clientName ?? '',
      clientEmail: initialData?.clientInfo?.clientEmail ?? '',
      clientPhone: formatUSPhoneNumber(initialData?.clientInfo?.clientPhone),
      ...initialData?.clientPortalAccess,
    },
  });

  const {
    register,
    handleSubmit,
    control,
    getValues,
    reset,
    watch,
    setValue,
    formState: { errors },
  } = useForm<ProjectFormData>({
    defaultValues: buildDefaults(),
  });

  const clientSameAsJobsite = watch('clientInfo.clientAddressSameAsJobsite');
  const inviteClientPortal = watch('clientPortalAccess.enabled');
  const clientInfoName = watch('clientInfo.clientName');
  const clientInfoEmail = watch('clientInfo.clientEmail');
  const clientInfoPhone = watch('clientInfo.clientPhone');

  const syncPortalAccessFromClientInfo = () => {
    const values = getValues();
    setValue('clientPortalAccess.clientName', values.clientInfo.clientName ?? '');
    setValue('clientPortalAccess.clientEmail', values.clientInfo.clientEmail ?? '');
    setValue(
      'clientPortalAccess.clientPhone',
      formatUSPhoneNumber(values.clientInfo.clientPhone ?? ''),
    );
  };

  useEffect(() => {
    if (!inviteClientPortal) return;
    syncPortalAccessFromClientInfo();
  }, [inviteClientPortal, clientInfoName, clientInfoEmail, clientInfoPhone]);

  useEffect(() => {
    if (!projectId) {
      setExistingPortal(null);
      setPortalLoading(false);
      return;
    }

    let cancelled = false;
    setPortalLoading(true);
    void fetchClientPortalByProjectId(projectId)
      .then((row) => {
        if (!cancelled) setExistingPortal(row);
      })
      .finally(() => {
        if (!cancelled) setPortalLoading(false);
      });

    return () => {
      cancelled = true;
    };
  }, [projectId]);

  useEffect(() => {
    reset(buildDefaults());
  }, [
    initialData?.name,
    initialData?.description,
    initialData?.pourDate,
    initialData?.jobsiteAddress?.street,
    initialData?.jobsiteAddress?.street2,
    initialData?.jobsiteAddress?.city,
    initialData?.jobsiteAddress?.state,
    initialData?.jobsiteAddress?.zip,
    initialData?.clientInfo?.clientName,
    initialData?.clientInfo?.clientCompany,
    hidePourDate,
    reset,
  ]);

  const runVerify = async (addr: USAddress): Promise<USAddress | null> => {
    const validation = validateUSAddress(addr, {
      requireStreet: true,
      requireZip: false,
    });
    if (!validation.ok) {
      setVerifyError(validation.errors.join(' '));
      setVerifiedLine(null);
      setVerifiedAddress(null);
      return null;
    }

    setVerifyLoading(true);
    setVerifyError(null);

    try {
      const result = await verifyJobsiteAddress(addr);
      setVerifiedLine(result.formattedAddress);
      const normalized = mergeVerifiedJobsiteAddress(copyUSAddress(addr), result.formattedAddress);
      setVerifiedAddress(normalized);
      reset({ ...getValues(), jobsiteAddress: normalized });
      return normalized;
    } catch (err) {
      setVerifyError(err instanceof Error ? err.message : 'Could not verify address.');
      setVerifiedLine(null);
      setVerifiedAddress(null);
      return null;
    } finally {
      setVerifyLoading(false);
    }
  };

  const handleVerifyClick = () => {
    void runVerify(getValues('jobsiteAddress'));
  };

  const onFormSubmit = async (data: ProjectFormData) => {
    setGenerateError(null);
    let jobsite = data.jobsiteAddress;

    if (requireVerifiedAddress && isUSAddressGeocodable(jobsite)) {
      if (verifiedAddress && verifiedLine) {
        jobsite = verifiedAddress;
      } else {
        const normalized = await runVerify(jobsite);
        if (!normalized) return;
        jobsite = normalized;
      }
    }

    let projectName = data.name.trim();

    if (!isEditing) {
      if (!user?.id) {
        setGenerateError('Sign in to create a project.');
        return;
      }
      setNameGenerating(true);
      setGeneratedNamePreview(null);
      try {
        const generated = await generateProjectName({
          scopeDescription: data.description,
          jobsiteAddress: sanitizeUSAddress(jobsite),
          userId: user.id,
          additionalNames: storeProjects.map((p) => p.name),
        });
        projectName = generated.name;
        setGeneratedNamePreview(generated.name);
      } catch (err) {
        setGenerateError(err instanceof Error ? err.message : 'Could not generate project name.');
        return;
      } finally {
        setNameGenerating(false);
      }
    } else if (!projectName) {
      setGenerateError('Project name is required.');
      return;
    }

    const payload: ProjectFormData = {
      ...data,
      name: projectName,
      jobsiteAddress: sanitizeUSAddress(jobsite),
      clientInfo: {
        ...data.clientInfo,
        clientName: data.clientInfo.clientName.trim(),
        clientCompany: data.clientInfo.clientCompany?.trim(),
        clientPhone: formatUSPhoneNumber(data.clientInfo.clientPhone?.trim()) || undefined,
        clientEmail: data.clientInfo.clientEmail?.trim(),
        clientAddressSameAsJobsite: data.clientInfo.clientAddressSameAsJobsite !== false,
        clientAddress:
          data.clientInfo.clientAddressSameAsJobsite === false
            ? sanitizeUSAddress(data.clientInfo.clientAddress ?? EMPTY_US_ADDRESS)
            : undefined,
      },
    };
    if (hidePourDate) delete payload.pourDate;

    if (payload.clientPortalAccess?.enabled) {
      const portalName =
        payload.clientPortalAccess.clientName.trim() || payload.clientInfo.clientName.trim();
      const portalEmail =
        payload.clientPortalAccess.clientEmail.trim() ||
        payload.clientInfo.clientEmail?.trim() ||
        '';
      if (!portalName || !portalEmail) {
        return;
      }
      payload.clientPortalAccess = {
        enabled: true,
        clientName: portalName,
        clientEmail: portalEmail,
        clientPhone:
          formatUSPhoneNumber(payload.clientPortalAccess.clientPhone?.trim()) ||
          formatUSPhoneNumber(payload.clientInfo.clientPhone?.trim()) ||
          undefined,
      };
    } else if (payload.clientPortalAccess) {
      payload.clientPortalAccess.enabled = false;
    }

    await onSubmit(payload);
  };

  const jobsiteState = watch('jobsiteAddress.state');
  const stateCodePreview = resolveStateCode(jobsiteState ?? '');
  const yearSuffix = String(new Date().getFullYear()).slice(-2);

  const formBody = (
    <form onSubmit={handleSubmit(onFormSubmit)} className="space-y-4">
      {isEditing ? (
        <Input
          label="Project Name"
          fullWidth
          error={errors.name?.message?.toString()}
          {...register('name', { required: 'Project name is required' })}
        />
      ) : (
        <div className="rounded-lg border border-cyan-200/60 bg-cyan-50/40 p-4 dark:border-cyan-800/50 dark:bg-cyan-950/20">
          <div className="flex items-start gap-2">
            <Sparkles className="h-5 w-5 shrink-0 text-cyan-600 dark:text-cyan-400 mt-0.5" />
            <div>
              <p className="text-sm font-semibold text-gray-900 dark:text-white">
                Auto project number & name
              </p>
              <p className="text-xs text-gray-600 dark:text-slate-400 mt-1">
                When you click Create Project, we assign the next number for the year with your
                jobsite state prefix
                {stateCodePreview ? (
                  <>
                    {' '}
                    (<span className="font-mono text-cyan-700 dark:text-cyan-300">
                      {stateCodePreview}
                      {yearSuffix}-###
                    </span>
                    )
                  </>
                ) : (
                  <> (e.g. GA26-201)</>
                )}{' '}
                and summarize your job scope into the title.
              </p>
              {generatedNamePreview && (
                <p className="mt-2 text-sm font-medium text-gray-900 dark:text-white">
                  {generatedNamePreview}
                </p>
              )}
            </div>
          </div>
        </div>
      )}

      {generateError && (
        <p className="text-sm text-red-600 dark:text-red-400" role="alert">
          {generateError}
        </p>
      )}

      <div className="rounded-lg border border-gray-200 dark:border-gray-700 p-4 space-y-4">
        <div>
          <h4 className="text-sm font-semibold text-gray-900 dark:text-white">
            Client information
          </h4>
          <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">
            Pre-fills the proposal client section when you generate a quote.
          </p>
        </div>
        <Input
          label="Client name"
          fullWidth
          error={errors.clientInfo?.clientName?.message?.toString()}
          {...register('clientInfo.clientName', {
            required: isEditing ? false : 'Client name is required',
          })}
        />
        <Input
          label="Client company"
          fullWidth
          {...register('clientInfo.clientCompany')}
        />
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <Controller
            name="clientInfo.clientPhone"
            control={control}
            render={({ field }) => (
              <Input
                label="Client phone"
                type="tel"
                fullWidth
                placeholder="(555) 555-5555"
                value={field.value ?? ''}
                onChange={(e) => field.onChange(formatUSPhoneInput(e.target.value))}
                onBlur={field.onBlur}
                ref={field.ref}
              />
            )}
          />
          <Input
            label="Client email"
            type="email"
            fullWidth
            {...register('clientInfo.clientEmail')}
          />
        </div>
        <Controller
          name="clientInfo.clientAddressSameAsJobsite"
          control={control}
          render={({ field }) => (
            <label className="flex items-center gap-2 text-sm text-gray-700 dark:text-gray-300">
              <input
                type="checkbox"
                className="rounded border-gray-300 dark:border-gray-600"
                checked={field.value !== false}
                onChange={(e) => field.onChange(e.target.checked)}
              />
              Client address same as jobsite
            </label>
          )}
        />
        {clientSameAsJobsite === false && (
          <Controller
            name="clientInfo.clientAddress"
            control={control}
            render={({ field }) => (
              <USAddressFields
                value={field.value ?? EMPTY_US_ADDRESS}
                onChange={field.onChange}
                showStreet2
                idPrefix="project-client"
              />
            )}
          />
        )}
      </div>

      <div className="rounded-lg border border-cyan-200/60 dark:border-cyan-800/50 bg-cyan-50/40 dark:bg-cyan-950/20 p-4 space-y-4">
        <div>
          <h4 className="text-sm font-semibold text-gray-900 dark:text-white">
            Client access
          </h4>
          <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">
            Invite your client to a read-only project dashboard — no account required.
          </p>
        </div>

        {portalLoading ? (
          <p className="text-sm text-gray-500 dark:text-gray-400">Checking client portal…</p>
        ) : existingPortal ? (
          <div className="rounded-md bg-white/70 dark:bg-slate-900/50 p-3 text-sm space-y-2">
            <p className="font-medium text-emerald-700 dark:text-emerald-300">
              Client portal is active
            </p>
            <p className="text-gray-600 dark:text-gray-300">
              Client: {existingPortal.clientName}
            </p>
            <p className="text-xs text-gray-500 dark:text-gray-400 break-all">
              {getClientPortalUrl(existingPortal.token)}
            </p>
            <p className="text-xs text-gray-500 dark:text-gray-400">
              Copy the link from project details after saving.
            </p>
          </div>
        ) : (
          <>
            <Controller
              name="clientPortalAccess.enabled"
              control={control}
              render={({ field }) => (
                <label className="flex items-center gap-2 text-sm text-gray-700 dark:text-gray-300">
                  <input
                    type="checkbox"
                    className="rounded border-gray-300 dark:border-gray-600"
                    checked={Boolean(field.value)}
                    onChange={(e) => {
                      const checked = e.target.checked;
                      field.onChange(checked);
                      if (checked) {
                        syncPortalAccessFromClientInfo();
                      }
                    }}
                  />
                  Invite client to view project dashboard
                </label>
              )}
            />
            {inviteClientPortal && (
              <>
                <p className="text-xs text-cyan-700 dark:text-cyan-300">
                  Pulled from client information above — updates as you edit those fields.
                </p>
                <Input
                  label="Client name"
                  fullWidth
                  readOnly
                  className="bg-slate-50 dark:bg-slate-800/50"
                  error={errors.clientPortalAccess?.clientName?.message?.toString()}
                  {...register('clientPortalAccess.clientName', {
                    required: inviteClientPortal
                      ? 'Client name is required for portal invite'
                      : false,
                  })}
                />
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <Input
                    label="Client email"
                    type="email"
                    fullWidth
                    readOnly
                    className="bg-slate-50 dark:bg-slate-800/50"
                    error={errors.clientPortalAccess?.clientEmail?.message?.toString()}
                    {...register('clientPortalAccess.clientEmail', {
