export default Settings;

import React from 'react';
import { useForm } from 'react-hook-form';
import { useNavigate, useLocation } from 'react-router-dom';
import { LogIn, Mail, Lock, ArrowLeft } from 'lucide-react';
import { useAuth } from '../../hooks/useAuth';
import Button from '../../components/ui/Button';
import Input from '../../components/ui/Input';
import Card from '../../components/ui/Card';
import { supabase } from '../../lib/supabase';
import backgroundImage from '../../assets/images/bkgrnd.jpg';

interface LoginForm {
  email: string;
  password: string;
}

const Login: React.FC = () => {
  const { signIn, refreshProfile } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const inviteToken =
    (location.state as { inviteToken?: string } | null)?.inviteToken ??
    new URLSearchParams(location.search).get('invite') ??
    undefined;
  const loginMessage = (location.state as { message?: string } | null)?.message;
  const { register, handleSubmit, formState: { errors }, setError, watch } = useForm<LoginForm>();
  const [isLoading, setIsLoading] = React.useState(false);
  const [resetEmailSent, setResetEmailSent] = React.useState(false);
  const [resetError, setResetError] = React.useState<string | null>(null);
  
  const emailValue = watch('email');

  const onSubmit = async (data: LoginForm) => {
    try {
      setIsLoading(true);
      await signIn(data.email, data.password);
      const { data: session } = await supabase.auth.getUser();
      if (inviteToken && session.user) {
        const { acceptInviteForCurrentUser } = await import('../../services/employeeService');
        try {
          await acceptInviteForCurrentUser(inviteToken);
          await refreshProfile();
          navigate('/employee/dashboard', { replace: true });
          return;
        } catch (err) {
          const msg = err instanceof Error ? err.message : 'Could not accept invite';
          setError('root', {
            message: `Signed in, but invite could not be applied: ${msg}`,
          });
          return;
        }
      }
      navigate('/', { replace: true });
    } catch {
      setError('root', {
        message: 'Invalid email or password'
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleForgotPassword = async () => {
    if (!emailValue) {
      setResetError('Please enter your email address first');
      return;
    }

    try {
      setIsLoading(true);
      setResetError(null);

      const origin = window.location.origin || `${window.location.protocol}//${window.location.host}`;
      
      const { error } = await supabase.auth.resetPasswordForEmail(emailValue, {
        redirectTo: `${origin}/reset-password`,
      });
      
      if (error) throw error;
      
      setResetEmailSent(true);
      setResetError(null);
    } catch (error: any) {
      setResetError(error.message || 'Error sending password reset email');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div 
      className="min-h-screen min-w-screen flex flex-col relative bg-white dark:bg-gray-900 overflow-hidden"
      style={{
        backgroundImage: `url(${backgroundImage})`,
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundRepeat: 'no-repeat',
        minHeight: '100dvh',
        minWidth: '100dvw',
        height: '100dvh',
        width: '100dvw',
        paddingTop: 'env(safe-area-inset-top)',
        paddingBottom: 'env(safe-area-inset-bottom)',
        paddingLeft: 'env(safe-area-inset-left)',
        paddingRight: 'env(safe-area-inset-right)'
      }}
    >
      <div className="absolute inset-0 bg-black/40 dark:bg-black/60" />
      
      <div className="relative z-10 p-4">
        <Button
          variant="ghost"
          onClick={() => navigate('/')}
          icon={<ArrowLeft size={20} />}
          className="text-white hover:text-blue-200"
        >
          Back
        </Button>
      </div>

      <div className="flex-1 flex items-center justify-center px-4 sm:px-6 lg:px-8 relative z-10 min-h-[100%] w-full">
        <Card className="w-full max-w-md p-8 my-auto">
          <div className="text-center mb-8">
            <LogIn className="mx-auto h-12 w-12 text-blue-600 dark:text-blue-400" />
            <h2 className="mt-6 text-3xl font-bold text-gray-900 dark:text-white">Sign in to your account</h2>
            <p className="mt-2 text-sm text-gray-600 dark:text-gray-300">
              Or{' '}
              <Button
                type="button"
                variant="ghost"
                onClick={() =>
                  navigate(
                    inviteToken
                      ? `/signup?invite=${encodeURIComponent(inviteToken)}`
                      : '/signup',
                  )
                }
                className="!inline !h-auto !p-0 !font-medium text-blue-600 hover:text-blue-500 dark:text-blue-400 dark:hover:text-blue-300"
              >
                create a new account
              </Button>
            </p>
          </div>

          {inviteToken && (
            <div className="mb-6 rounded-md border border-cyan-200 bg-cyan-50 p-3 text-sm text-cyan-900 dark:border-cyan-800 dark:bg-cyan-950/40 dark:text-cyan-100">
              Sign in with the email address that received the team invite to join your company.
            </div>
          )}

          {loginMessage && (
            <div className="mb-6 rounded-md border border-green-200 bg-green-50 p-3 text-sm text-green-900 dark:border-green-800 dark:bg-green-950/40 dark:text-green-100">
              {loginMessage}
            </div>
          )}

          {resetEmailSent ? (
            <div className="bg-green-50 dark:bg-green-900/30 border border-green-200 dark:border-green-800 rounded-md p-4 text-center">
              <p className="text-green-800 dark:text-green-200">
                If an account exists with {emailValue}, password reset instructions have been sent.
                Please check your email inbox.
              </p>
            </div>
          ) : (
            <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
              <Input
                label="Email address"
                type="email"
                icon={<Mail className="h-5 w-5 text-gray-400 dark:text-gray-500" />}
                error={errors.email?.message}
                {...register('email', {
                  required: 'Email is required',
                  pattern: {
                    value: /^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}$/i,
                    message: 'Invalid email address'
                  }
                })}
                fullWidth
              />

              <div>
                <Input
                  label="Password"
                  type="password"
                  icon={<Lock className="h-5 w-5 text-gray-400 dark:text-gray-500" />}
                  error={errors.password?.message}
                  {...register('password', {
                    required: 'Password is required',
                    minLength: {
                      value: 6,
                      message: 'Password must be at least 6 characters'
                    }
                  })}
                  fullWidth
                />
                <div className="mt-2 flex flex-col space-y-2">
                  <Button
                    type="button"
                    variant="ghost"
                    size="sm"
                    onClick={handleForgotPassword}
                    className="!h-auto !p-0 text-blue-600 hover:text-blue-500 dark:text-blue-400 dark:hover:text-blue-300"
                  >
                    Forgot your password?
                  </Button>
                  {resetError && (
                    <p className="text-sm text-red-600 dark:text-red-400">
                      {resetError}
                    </p>
                  )}
                </div>
              </div>

              {errors.root && (
                <p className="text-sm text-red-600 dark:text-red-400 text-center">
                  {errors.root.message}
                </p>
              )}

              <Button
                type="submit"
                fullWidth
                isLoading={isLoading}
                icon={<LogIn size={18} />}
              >
                Sign in
              </Button>
            </form>
          )}
        </Card>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useMemo } from 'react';
import { motion } from 'framer-motion';
import { useNavigate, useLocation } from 'react-router-dom';
import ProjectCalculatorShell from '../../components/calculators/ProjectCalculatorShell';
import ReinforcementOptimizer from '../../components/optimizer/ReinforcementOptimizer';
import RebarPricingCatalog from '../../components/rebar/RebarPricingCatalog';
import Input from '../../components/ui/Input';
import Card from '../../components/ui/Card';
import Button from '../../components/ui/Button';
import { useProjectStore } from '../../store';
import { regionalMultiplierKeyFromAddress } from '../../data/regionalMultipliers';
import {
  getWorkflowProjectId,
  isWorkflowActive,
  workflowQuery,
  workflowNavigateState,
  type WorkflowLocationState,
} from '../../utils/workflow';

const ReinforcementCalculatorPage: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const workflowState = location.state as WorkflowLocationState | null;
  const inWorkflow = isWorkflowActive(location.search, workflowState);
  const workflowProjectId = getWorkflowProjectId(location.search, workflowState);
  const { currentProject, loadProjects, setCurrentProject } = useProjectStore();

  const regionalKey = regionalMultiplierKeyFromAddress(currentProject?.jobsiteAddress);

  const latestConcrete = currentProject?.calculations
    ?.filter((c) => c.result?.volume > 0)
    .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())[0];

  const [lengthFt, setLengthFt] = useState('');
  const [widthFt, setWidthFt] = useState('');
  const [thicknessIn, setThicknessIn] = useState('6');
  const [heightFt, setHeightFt] = useState('');
  const [isColumn, setIsColumn] = useState(false);
  const [showOptimizer, setShowOptimizer] = useState(false);

  const calculatorData = useMemo(() => {
    const length = parseFloat(lengthFt) || 0;
    const width = parseFloat(widthFt) || 0;
    const thickness = parseFloat(thicknessIn) || 6;
    const height = parseFloat(heightFt) || 0;
    const cubicYards =
      latestConcrete?.result?.volume ??
      (length * width * (thickness / 12)) / 27;
    return {
      length_ft: length,
      width_ft: width,
      thickness_in: thickness,
      cubicYards,
      height_ft: isColumn ? height : undefined,
    };
  }, [lengthFt, widthFt, thicknessIn, heightFt, isColumn, latestConcrete]);

  const canRun =
    calculatorData.length_ft > 0 &&
    calculatorData.width_ft > 0 &&
    calculatorData.thickness_in > 0 &&
    (!isColumn || (calculatorData.height_ft ?? 0) > 0);

  React.useEffect(() => {
    const d = latestConcrete?.dimensions;
    if (!d) return;
    if (d.length) setLengthFt(String(d.length));
    if (d.width) setWidthFt(String(d.width));
    if (d.thickness) setThicknessIn(String(Math.round(d.thickness * 12)));
    if (d.height) {
      setHeightFt(String(d.height));
      setIsColumn(true);
    }
    if (latestConcrete?.type === 'column') setIsColumn(true);
  }, [latestConcrete?.id]);

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
      <ProjectCalculatorShell
        title="Reinforcement Calculator"
        description="Design rebar from 2026 stick pricing — cost saves to your project for proposals."
      >
        <Card className="p-6 mb-6">
          <RebarPricingCatalog activeRegionalKey={regionalKey} />
        </Card>

        <Card className="p-6 mb-6">
          <h2 className="text-lg font-semibold text-gray-900 dark:text-white mb-4">
            Footprint
          </h2>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <Input
              label="Length (ft)"
              type="number"
              min="0"
              value={lengthFt}
              onChange={(e) => setLengthFt(e.target.value)}
            />
            <Input
              label="Width (ft)"
              type="number"
              min="0"
              value={widthFt}
              onChange={(e) => setWidthFt(e.target.value)}
            />
            <Input
              label="Thickness (in)"
              type="number"
              min="0"
              value={thicknessIn}
              onChange={(e) => setThicknessIn(e.target.value)}
            />
            <label className="flex items-center gap-2 text-sm text-gray-700 dark:text-gray-300 sm:col-span-2">
              <input
                type="checkbox"
                checked={isColumn}
                onChange={(e) => setIsColumn(e.target.checked)}
                className="rounded border-gray-300"
              />
              Column / vertical member
            </label>
            {isColumn && (
              <Input
                label="Height (ft)"
                type="number"
                min="0"
                value={heightFt}
                onChange={(e) => setHeightFt(e.target.value)}
              />
            )}
          </div>
          <p className="text-sm text-gray-600 dark:text-gray-400 mt-4">
            Material cost is calculated from your cut list (20 ft sticks) and saved to{' '}
            <code className="text-xs">reinforcement_sets.pricing</code> when you save the design.
          </p>
          <Button
            type="button"
            className="mt-4"
            disabled={!canRun}
            onClick={() => setShowOptimizer(true)}
          >
            Open reinforcement designer
          </Button>
        </Card>

        {showOptimizer && canRun && (
          <ReinforcementOptimizer
            embedded
            calculatorData={calculatorData}
            projectName={currentProject?.name}
            isColumn={isColumn}
            onClose={() => setShowOptimizer(false)}
            onSaved={async () => {
              setShowOptimizer(false);
              const projectId = currentProject?.id;
              await loadProjects();
              if (projectId) setCurrentProject(projectId);
            }}
          />
        )}

        {inWorkflow && (
          <Button
            variant="secondary"
            className="mt-4 shadow-sm"
            onClick={() =>
              navigate({
                pathname: '/calculator',
                search: workflowQuery(workflowProjectId),
                state: workflowNavigateState(workflowProjectId),
              })
            }
          >
            Back to all calculators
          </Button>
        )}
      </ProjectCalculatorShell>
    </motion.div>
  );
};

export default ReinforcementCalculatorPage;

import React, { useEffect, useState } from 'react';
import { useAuth } from '../../hooks/useAuth';
import {
  fetchMessagesForUser,
  markMessageRead,
  sendFieldMessage,
} from '../../services/fieldMessageService';
import type { FieldMessage } from '../../types/fieldPlanner';
import { fetchAssignedProjects } from '../../services/employeeService';
import Button from '../../components/ui/Button';
import Select from '../../components/ui/Select';

export default function EmployeeMessagesPage() {
  const { user, isOwner } = useAuth();
  const [messages, setMessages] = useState<FieldMessage[]>([]);
  const [projects, setProjects] = useState<{ id: string; name: string }[]>([]);
  const [projectId, setProjectId] = useState('');
  const [text, setText] = useState('');
  const [busy, setBusy] = useState(false);

  const reload = async () => {
    if (!user) return;
    const msgs = await fetchMessagesForUser(user.id, isOwner);
    setMessages(msgs);
    if (!isOwner) {
      const p = await fetchAssignedProjects(user.id);
      setProjects(p.map((x) => ({ id: x.id, name: x.name })));
      if (!projectId && p[0]) setProjectId(p[0].id);
    }
  };

  useEffect(() => {
    void reload();
  }, [user, isOwner]);

  const handleSend = async () => {
    if (!user || !projectId || !text.trim()) return;
    setBusy(true);
    try {
      await sendFieldMessage({
        projectId,
        senderId: user.id,
        message: text.trim(),
      });
      setText('');
      await reload();
    } finally {
      setBusy(false);
    }
  };

  return (
    <div className="space-y-4">
      <h1 className="text-xl font-bold text-white">Messages</h1>

      <ul className="space-y-2 max-h-[50vh] overflow-y-auto">
        {messages.map((m) => (
          <li
            key={m.id}
            className={`rounded-lg border p-3 ${
              m.isRead ? 'border-slate-700 bg-slate-800/50' : 'border-cyan-500/40 bg-cyan-950/20'
            }`}
          >
            <p className="text-xs text-slate-400">
              {m.projectName} · {m.senderName}
            </p>
            <p className="text-sm text-slate-100 mt-1">{m.message}</p>
            <p className="text-xs text-slate-500 mt-1">
              {new Date(m.createdAt).toLocaleString()}
            </p>
            {!m.isRead && m.recipientId === user?.id && (
              <button
                type="button"
                className="mt-2 text-xs text-cyan-400"
                onClick={() => void markMessageRead(m.id).then(reload)}
              >
                Mark read
              </button>
            )}
          </li>
        ))}
        {messages.length === 0 && <p className="text-sm text-slate-500">No messages.</p>}
      </ul>

      {!isOwner && projects.length > 0 && (
        <div className="space-y-2 border-t border-slate-700 pt-4">
          <Select
            label="Project"
            value={projectId}
            onChange={setProjectId}
            options={projects.map((p) => ({ value: p.id, label: p.name }))}
          />
          <textarea
            value={text}
            onChange={(e) => setText(e.target.value)}
            placeholder="Message to office…"
            rows={3}
            className="w-full rounded-lg border border-slate-600 bg-slate-800 px-3 py-2 text-sm text-white"
          />
          <Button
            variant="accent"
            fullWidth
            className="min-h-[48px]"
            onClick={() => void handleSend()}
            disabled={busy}
          >
            Send
          </Button>
        </div>
      )}
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { useAuth } from '../../hooks/useAuth';
import { usePlannerProject } from '../../contexts/PlannerProjectContext';
import {
  assignEmployeeToProject,
  fetchAssignmentsForProject,
  removeEmployeeFromProject,
} from '../../services/employeeService';
import { fetchTeamProfiles, DEFAULT_PROFILE_DISPLAY_NAME } from '../../services/profileService';
import type { EmployeeProjectAssignment, Profile } from '../../types/fieldPlanner';
import Button from '../../components/ui/Button';
import UserAvatar from '../../components/planner/UserAvatar';
import { PLANNER_MUTED, PLANNER_PAGE_BG, PLANNER_SECTION_TITLE } from '../../components/planner/plannerTheme';

export default function PlannerTeamPage() {
  const { user } = useAuth();
  const { projectId, team, isOwner, reload } = usePlannerProject();
  const [assignments, setAssignments] = useState<EmployeeProjectAssignment[]>([]);
  const [available, setAvailable] = useState<Profile[]>([]);
  const [selectedEmployee, setSelectedEmployee] = useState('');

  const loadAssignments = async () => {
    const rows = await fetchAssignmentsForProject(projectId);
    setAssignments(rows);
  };

  useEffect(() => {
    void loadAssignments();
  }, [projectId]);

  useEffect(() => {
    if (!user || !isOwner) return;
    void fetchTeamProfiles(user.id).then((members) => {
      const assigned = new Set(assignments.map((a) => a.employeeId));
      setAvailable(members.filter((m) => !assigned.has(m.id)));
    });
  }, [user, isOwner, assignments]);

  const profileFor = (employeeId: string) => team.find((p) => p.id === employeeId);

  const handleAssign = async () => {
    if (!user || !selectedEmployee) return;
    await assignEmployeeToProject(selectedEmployee, projectId, user.id);
    setSelectedEmployee('');
    await loadAssignments();
    void reload();
  };

  const handleRemove = async (assignmentId: string) => {
    await removeEmployeeFromProject(assignmentId);
    await loadAssignments();
    void reload();
  };

  return (
    <div className={`${PLANNER_PAGE_BG} flex-1 overflow-y-auto p-4 sm:p-6`}>
      <h2 className={`mb-4 ${PLANNER_SECTION_TITLE}`}>Team</h2>

      {isOwner && (
        <div className="mb-6 flex flex-col gap-2 rounded-xl border border-slate-200 bg-white p-4 dark:border-slate-700 dark:bg-slate-900 sm:flex-row sm:items-end">
          <label className="flex-1 text-sm">
            <span className="mb-1 block font-medium text-gray-700 dark:text-slate-300">
              Assign employee
            </span>
            <select
              value={selectedEmployee}
              onChange={(e) => setSelectedEmployee(e.target.value)}
              className="w-full rounded-lg border border-slate-300 px-3 py-2 text-sm dark:border-slate-600 dark:bg-slate-800"
            >
              <option value="">Select team member…</option>
              {available.map((m) => (
                <option key={m.id} value={m.id}>
                  {m.displayName ?? m.id}
                </option>
              ))}
            </select>
          </label>
          <Button size="sm" onClick={() => void handleAssign()} disabled={!selectedEmployee}>
            Assign
          </Button>
        </div>
      )}

      {assignments.length === 0 && <p className={PLANNER_MUTED}>No employees assigned to this project.</p>}

      <ul className="space-y-2">
        {assignments.map((a) => {
          const profile = profileFor(a.employeeId);
          const name = profile?.displayName ?? DEFAULT_PROFILE_DISPLAY_NAME;
          return (
            <li
              key={a.id}
              className="flex items-center justify-between rounded-xl border border-slate-200 bg-white px-4 py-3 dark:border-slate-700 dark:bg-slate-900"
            >
              <div className="flex items-center gap-3">
                <UserAvatar name={name} size="md" />
                <div>
                  <p className="font-medium text-gray-900 dark:text-white">{name}</p>
                  <p className="text-xs capitalize text-gray-500 dark:text-slate-400">{a.role}</p>
                </div>
              </div>
              {isOwner && (
                <Button size="sm" variant="outline" onClick={() => void handleRemove(a.id)}>
                  Remove
                </Button>
              )}
            </li>
          );
        })}
      </ul>
    </div>
  );
}

import React, { useCallback, useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { ClipboardList } from 'lucide-react';
import { useSearchParams } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import { useProjectStore, useSettingsStore } from '../../store';
import { formatUSAddress, hasProjectJobsite } from '../../types/address';
import type { ConcreteInspectionChecklist } from '../../types/fieldTools';
import {
  fetchConcreteInspection,
  upsertConcreteInspection,
} from '../../services/concreteInspectionService';
import { exportConcreteInspectionPdf } from '../../utils/concreteInspectionPdf';
import FieldToolPageLayout from '../../components/tools/FieldToolPageLayout';
import ToolSectionCard from '../../components/tools/ToolSectionCard';
import InspectionChecklistSection from '../../components/tools/InspectionChecklistSection';
import FieldToolStickyActions from '../../components/tools/FieldToolStickyActions';
import SignatureBlock from '../../components/change-order/SignatureBlock';
import Input from '../../components/ui/Input';
import Toast from '../../components/ui/Toast';
import { FIELD_TOOL_MUTED } from '../../components/tools/fieldToolTheme';
import { emptyConcreteInspection } from './inspectionDefaults';

const ACI_NOTE =
  'This checklist is general field guidance based on common concrete quality practices and references ACI 301 and ACI 318 concepts. Always follow the project specifications, approved drawings, local code, and engineer of record requirements.';

export default function ConcreteInspectionChecklistPage() {
  const { user } = useAuth();
  const [searchParams, setSearchParams] = useSearchParams();
  const { currentProject, setCurrentProject } = useProjectStore();
  const { companySettings } = useSettingsStore();
  const [checklist, setChecklist] = useState<ConcreteInspectionChecklist>(emptyConcreteInspection);
  const [inspectorName, setInspectorName] = useState('');
  const [contractorName, setContractorName] = useState('');
  const [saving, setSaving] = useState(false);
  const [exporting, setExporting] = useState(false);
  const [toast, setToast] = useState<{ title: string; message: string; type: 'success' | 'error' } | null>(
    null,
  );

  const recordId = searchParams.get('id');

  useEffect(() => {
    if (!recordId) return;
    void fetchConcreteInspection(recordId).then((row) => {
      if (!row) return;
      setChecklist(row);
      setInspectorName(row.inspector);
      setContractorName(row.contractor);
      if (row.projectId) setCurrentProject(row.projectId);
    });
  }, [recordId]);

  const applyProjectPrefill = useCallback((projectId: string | null) => {
    if (!projectId) {
      setChecklist((c) => ({ ...c, projectId: null }));
      return;
    }
    const project = useProjectStore.getState().projects.find((p) => p.id === projectId);
    if (!project) return;
    setChecklist((c) => ({
      ...c,
      projectId,
      projectName: project.name,
      projectAddress: hasProjectJobsite(project.jobsiteAddress)
        ? formatUSAddress(project.jobsiteAddress)
        : c.projectAddress,
    }));
  }, []);

  useEffect(() => {
    if (currentProject?.id) applyProjectPrefill(currentProject.id);
  }, [currentProject?.id, applyProjectPrefill]);

  const patch = (patch: Partial<ConcreteInspectionChecklist>) =>
    setChecklist((c) => ({ ...c, ...patch }));

  const companyHeader = {
    companyName: companySettings.companyName || '',
    address: companySettings.address || '',
    phone: companySettings.phone || '',
    email: companySettings.email || '',
  };

  const handleSave = async () => {
    if (!user?.id) {
      setToast({ title: 'Sign in required', message: 'Log in to save checklists.', type: 'error' });
      return;
    }
    const projectId = currentProject?.id ?? checklist.projectId ?? null;
    if (!projectId) {
      setToast({
        title: 'Select a project',
        message: 'Choose a project so this checklist appears in Planner → Documents.',
        type: 'error',
      });
      return;
    }
    setSaving(true);
    try {
      const saved = await upsertConcreteInspection(
        {
          ...checklist,
          inspector: inspectorName || checklist.inspector,
          contractor: contractorName || checklist.contractor,
          projectId,
        },
        user.id,
      );
      setChecklist(saved);
      if (saved.id) {
        const next = new URLSearchParams();
        next.set('id', saved.id);
        next.set('project', projectId);
        setSearchParams(next, { replace: true });
      }
      const projectName = currentProject?.name ?? checklist.projectName;
      setToast({
        title: 'Saved',
        message: `Checklist saved to Planner documents for ${projectName}.`,
        type: 'success',
      });
    } catch (e) {
      console.error(e);
      setToast({ title: 'Save failed', message: 'Could not save. Try again.', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const handleExportPdf = async () => {
    setExporting(true);
    try {
      await exportConcreteInspectionPdf(
        {
          ...checklist,
          inspector: inspectorName || checklist.inspector,
          contractor: contractorName || checklist.contractor,
        },
        companyHeader,
      );
    } catch (e) {
      console.error(e);
      setToast({ title: 'Export failed', message: 'Could not generate PDF.', type: 'error' });
    } finally {
      setExporting(false);
    }
  };

  const handleClear = () => {
    if (!window.confirm('Clear all fields on this form?')) return;
    setChecklist(emptyConcreteInspection());
    setInspectorName('');
    setContractorName('');
    setSearchParams({}, { replace: true });
    if (currentProject?.id) applyProjectPrefill(currentProject.id);
  };

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
      <FieldToolPageLayout
        title="Concrete Inspection Checklist"
        subtitle="Pre-Placement, Placing, Post Placement"
        icon={ClipboardList}
        onProjectPrefill={applyProjectPrefill}
        actions={
          <FieldToolStickyActions
            onSave={() => void handleSave()}
            onPrint={() => window.print()}
            onExportPdf={() => void handleExportPdf()}
            onClear={handleClear}
            saving={saving}
            exporting={exporting}
            saveLabel="Save Checklist"
          />
        }
      >
        <ToolSectionCard eyebrow="Section 1" title="Project information">
          <div className="grid gap-3 sm:grid-cols-2">
            <Input
              label="Project name"
              value={checklist.projectName}
              onChange={(e) => patch({ projectName: e.target.value })}
              fullWidth
            />
            <Input
              label="Date"
              type="date"
              value={checklist.inspectionDate}
              onChange={(e) => patch({ inspectionDate: e.target.value })}
              fullWidth
            />
            <div className="sm:col-span-2">
              <Input
                label="Project address"
                value={checklist.projectAddress}
                onChange={(e) => patch({ projectAddress: e.target.value })}
                fullWidth
              />
            </div>
            <Input
              label="Inspector"
              value={checklist.inspector}
              onChange={(e) => {
                setInspectorName(e.target.value);
                patch({ inspector: e.target.value });
              }}
              fullWidth
            />
            <Input
              label="Contractor"
              value={checklist.contractor}
              onChange={(e) => {
                setContractorName(e.target.value);
                patch({ contractor: e.target.value });
              }}
              fullWidth
            />
            <Input
              label="Mix design / PSI"
              value={checklist.mixDesign}
              onChange={(e) => patch({ mixDesign: e.target.value })}
              fullWidth
            />
            <Input
              label="Placement type"
              value={checklist.placementType}
              onChange={(e) => patch({ placementType: e.target.value })}
              fullWidth
            />
            <Input
              label="Pour area"
              value={checklist.pourArea}
              onChange={(e) => patch({ pourArea: e.target.value })}
              fullWidth
            />
            <Input
              label="Estimated cubic yards"
              type="number"
              min={0}
              step="0.1"
              value={checklist.estimatedYards}
              onChange={(e) => patch({ estimatedYards: e.target.value })}
              fullWidth
            />
          </div>
        </ToolSectionCard>

        <ToolSectionCard eyebrow="Section 2" title="Pre-pour checklist">
          <InspectionChecklistSection
            items={checklist.prePourItems}
            onChange={(prePourItems) => patch({ prePourItems })}
          />
        </ToolSectionCard>

        <ToolSectionCard eyebrow="Section 3" title="During placement checklist">
          <InspectionChecklistSection
            items={checklist.duringPlacementItems}
            onChange={(duringPlacementItems) => patch({ duringPlacementItems })}
          />
        </ToolSectionCard>

        <ToolSectionCard eyebrow="Section 4" title="Post-placement checklist">
          <InspectionChecklistSection
            items={checklist.postPlacementItems}
            onChange={(postPlacementItems) => patch({ postPlacementItems })}
          />
        </ToolSectionCard>

        <div className="rounded-xl border border-amber-500/30 bg-amber-50/40 p-4 dark:border-amber-500/20 dark:bg-amber-950/20">
          <p className="text-xs font-semibold uppercase tracking-wide text-amber-800 dark:text-amber-300">
            ACI reference note
          </p>
          <p className={`mt-2 text-sm ${FIELD_TOOL_MUTED}`}>{ACI_NOTE}</p>
        </div>

        <ToolSectionCard eyebrow="Section 5" title="General notes">
          <Input
            label="Notes"
            value={checklist.notes}
            onChange={(e) => patch({ notes: e.target.value })}
            fullWidth
          />
        </ToolSectionCard>

        <ToolSectionCard eyebrow="Section 6" title="Signatures">
          <div className="grid gap-6 lg:grid-cols-2">
            <SignatureBlock
              title="Inspector"
              name={inspectorName}
              signature={checklist.inspectorSignature}
              onNameChange={(v) => {
                setInspectorName(v);
                patch({ inspector: v });
              }}
              onSignatureChange={(v) => patch({ inspectorSignature: v })}
            />
            <SignatureBlock
              title="Contractor"
              name={contractorName}
              signature={checklist.contractorSignature}
              onNameChange={(v) => {
                setContractorName(v);
                patch({ contractor: v });
              }}
              onSignatureChange={(v) => patch({ contractorSignature: v })}
            />
          </div>
        </ToolSectionCard>
      </FieldToolPageLayout>

      {toast && (
        <Toast
          id="inspection-toast"
          title={toast.title}
          message={toast.message}
          type={toast.type}
          onClose={() => setToast(null)}
        />
      )}
    </motion.div>
  );
}

import React, { useCallback, useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { ShieldCheck } from 'lucide-react';
import { useSearchParams } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import { useProjectStore, useSettingsStore } from '../../store';
import { formatUSAddress, hasProjectJobsite } from '../../types/address';
import type { SafetyMeeting } from '../../types/fieldTools';
import { fetchSafetyMeeting, upsertSafetyMeeting } from '../../services/safetyMeetingService';
import { exportSafetyMeetingPdf } from '../../utils/safetyMeetingPdf';
import FieldToolPageLayout from '../../components/tools/FieldToolPageLayout';
import ToolSectionCard from '../../components/tools/ToolSectionCard';
import JhaRowsEditor from '../../components/tools/JhaRowsEditor';
import ToolboxTalkSection from '../../components/tools/ToolboxTalkSection';
import AttendanceRowsEditor from '../../components/tools/AttendanceRowsEditor';
import FieldToolStickyActions from '../../components/tools/FieldToolStickyActions';
import Input from '../../components/ui/Input';
import Toast from '../../components/ui/Toast';
import { emptySafetyMeeting } from './safetyMeetingDefaults';

export default function SafetyMeetingToolPage() {
  const { user } = useAuth();
  const [searchParams, setSearchParams] = useSearchParams();
  const { currentProject, setCurrentProject } = useProjectStore();
  const { companySettings } = useSettingsStore();
  const [meeting, setMeeting] = useState<SafetyMeeting>(emptySafetyMeeting);
  const [saving, setSaving] = useState(false);
  const [exporting, setExporting] = useState(false);
  const [toast, setToast] = useState<{ title: string; message: string; type: 'success' | 'error' } | null>(
    null,
  );

  const recordId = searchParams.get('id');

  useEffect(() => {
    if (!recordId) return;
    void fetchSafetyMeeting(recordId).then((row) => {
      if (!row) return;
      setMeeting(row);
      if (row.projectId) setCurrentProject(row.projectId);
    });
  }, [recordId]);

  const applyProjectPrefill = useCallback(
    (projectId: string | null) => {
      if (!projectId) {
        setMeeting((m) => ({ ...m, projectId: null }));
        return;
      }
      const project = useProjectStore.getState().projects.find((p) => p.id === projectId);
      if (!project) return;
      setMeeting((m) => ({
        ...m,
        projectId,
        projectName: project.name,
        projectAddress: hasProjectJobsite(project.jobsiteAddress)
          ? formatUSAddress(project.jobsiteAddress)
          : m.projectAddress,
        companyName: m.companyName || companySettings.companyName || '',
      }));
    },
    [companySettings.companyName],
  );

  useEffect(() => {
    if (currentProject?.id) applyProjectPrefill(currentProject.id);
  }, [currentProject?.id, applyProjectPrefill]);

  const patch = (patch: Partial<SafetyMeeting>) => setMeeting((m) => ({ ...m, ...patch }));

  const companyHeader = {
    companyName: companySettings.companyName || meeting.companyName,
    address: companySettings.address || '',
    phone: companySettings.phone || '',
    email: companySettings.email || '',
  };

  const handleSave = async () => {
    if (!user?.id) {
      setToast({ title: 'Sign in required', message: 'Log in to save safety meetings.', type: 'error' });
      return;
    }
    const projectId = currentProject?.id ?? meeting.projectId ?? null;
    if (!projectId) {
      setToast({
        title: 'Select a project',
        message: 'Choose a project so this safety meeting appears in Planner → Documents.',
        type: 'error',
      });
      return;
    }
    setSaving(true);
    try {
      const saved = await upsertSafetyMeeting({ ...meeting, projectId }, user.id);
      setMeeting(saved);
      if (saved.id) {
        const next = new URLSearchParams();
        next.set('id', saved.id);
        next.set('project', projectId);
        setSearchParams(next, { replace: true });
      }
      const projectName = currentProject?.name ?? meeting.projectName;
      setToast({
        title: 'Saved',
        message: `Safety meeting saved to Planner documents for ${projectName}.`,
        type: 'success',
      });
    } catch (e) {
      console.error(e);
      setToast({ title: 'Save failed', message: 'Could not save. Try again.', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const handleExportPdf = async () => {
    setExporting(true);
    try {
      await exportSafetyMeetingPdf(meeting, companyHeader);
    } catch (e) {
      console.error(e);
      setToast({ title: 'Export failed', message: 'Could not generate PDF.', type: 'error' });
    } finally {
      setExporting(false);
    }
  };

  const handleClear = () => {
    if (!window.confirm('Clear all fields on this form?')) return;
    setMeeting(emptySafetyMeeting());
