/** null = unknown, false = migration not applied yet */
let projectJobsiteColumnsAvailable: boolean | null = null;

function isClientInfoColumnError(message: string): boolean {
  return message.includes('client_info');
}

function isJobsiteColumnError(message: string): boolean {
  return (
    message.includes('jobsite_street') ||
    message.includes('jobsite_city') ||
    message.includes('jobsite_state') ||
    message.includes('jobsite_zip')
  );
}

function isTruckTicketsSchemaError(message: string): boolean {
  return message.includes('truck_tickets') || message.includes('schema cache');
}

function isPlacementOrderColumnError(message: string): boolean {
  return message.includes('placement_order');
}

function isCustomEstimatesColumnError(message: string): boolean {
  return message.includes('custom_estimates');
}

function isWasteFactorColumnError(message: string): boolean {
  return message.includes('waste_factor');
}

function isMixProfileColumnError(message: string): boolean {
  return message.includes('mix_profile');
}

function isPourDateColumnError(message: string): boolean {
  return message.includes('pour_date');
}

function isProjectsUserFkError(message: string): boolean {
  const lower = message.toLowerCase();
  return (
    lower.includes('projects_user_id_fkey') ||
    (lower.includes('foreign key') && lower.includes('user_id'))
  );
}
function omitPayloadKeys(
  payload: Record<string, unknown>,
  keys: string[],
): Record<string, unknown> {
  const next = { ...payload };
  for (const key of keys) {
    delete next[key];
  }
  return next;
}

function stripJobsiteFromPayload(body: Record<string, unknown>): Record<string, unknown> {
  return omitPayloadKeys(body, [
    'jobsite_street',
    'jobsite_street2',
    'jobsite_city',
    'jobsite_state',
    'jobsite_zip',
  ]);
}

function isLaborEstimatesSchemaError(message: string): boolean {
  return message.includes('labor_estimates');
}

function shouldFallbackLaborToPlacementOrder(error: {
  message?: string;
  code?: string;
}): boolean {
  const msg = (error.message ?? '').toLowerCase();
  if (isLaborEstimatesSchemaError(msg)) return true;
  if (msg.includes('row-level security') || msg.includes('permission denied')) {
    return true;
  }
  if (error.code === '42P01' || error.code === 'PGRST204' || error.code === 'PGRST205') {
    return true;
  }
  return false;
}

function isRecoverableProjectSelectError(message: string): boolean {
  return (
    isJobsiteColumnError(message) ||
    isClientInfoColumnError(message) ||
    isTruckTicketsSchemaError(message) ||
    isPlacementOrderColumnError(message) ||
    isLaborEstimatesSchemaError(message) ||
    isCustomEstimatesColumnError(message)
  );
}

function supabaseErrorMessage(err: unknown): string {
  if (err && typeof err === 'object' && 'message' in err) {
    return String((err as { message: string }).message);
  }
  if (err instanceof Error) return err.message;
  return String(err);
}

/** User-facing message when project create/update load fails. */
export function projectSaveErrorMessage(err: unknown): string {
  const msg = supabaseErrorMessage(err);
  if (isProjectsUserFkError(msg)) {
    return 'Database fix required — in Supabase SQL Editor run migration 20260607000000_fix_projects_user_reference.sql (links projects to your login account).';
  }
  if (isCustomEstimatesColumnError(msg)) {
    return 'Database update required — run migration 20260606000000_project_custom_estimates.sql in Supabase';
  }
  if (isClientInfoColumnError(msg)) {
    return 'Database update required — run migration 20260530120000_project_client_info.sql in Supabase';
  }
  if (msg.toLowerCase().includes('row-level security') || msg.toLowerCase().includes('permission denied')) {
    return 'You do not have permission to create projects. Sign in as the account owner.';
  }
  return msg || 'Could not save project';
}

/** User-facing message when labor save fails (after any fallback attempt). */
export function laborSaveErrorMessage(err: unknown): string {
  const msg =
    err && typeof err === 'object' && 'message' in err
      ? String((err as { message: string }).message)
      : err instanceof Error
        ? err.message
        : String(err);
  if (isLaborEstimatesSchemaError(msg)) {
    return 'Labor table missing — run Supabase migration 20250526120000_labor_estimates_reinforcement_pricing.sql';
  }
  if (msg.toLowerCase().includes('row-level security')) {
    return 'Labor table blocked by RLS — run migration 20250526120100_labor_estimates_rls.sql in Supabase SQL editor';
  }
  return msg || 'Could not save labor estimate';
}

function parsePlacementOrder(raw: unknown): PlacementOrder | undefined {
  if (!raw || typeof raw !== 'object') return undefined;
  const o = raw as PlacementOrder;
  if (!o.status || !o.contact) return undefined;
  return o;
}

async function fetchProjectRows() {
  const selects = [
    PROJECT_SELECT,
    PROJECT_SELECT_NO_CLIENT_INFO,
    PROJECT_SELECT_NO_LABOR_ESTIMATES,
    PROJECT_SELECT_NO_LABOR_ESTIMATES_NO_CLIENT,
    PROJECT_SELECT_NO_PLACEMENT_ORDER,
    PROJECT_SELECT_NO_JOBSITE,
    PROJECT_SELECT_LEGACY,
  ];

  for (let i = 0; i < selects.length; i++) {
    const result = await supabase
      .from('projects')
      .select(selects[i])
      .order('created_at', { ascending: false });

    if (!result.error) {
      if (selects[i] === PROJECT_SELECT) {
        projectJobsiteColumnsAvailable = true;
      } else if (selects[i] === PROJECT_SELECT_NO_JOBSITE) {
        projectJobsiteColumnsAvailable = false;
        console.warn(
          'Project jobsite address columns missing — run Supabase migration 20250525130000_project_jobsite_address.sql',
        );
      } else if (selects[i] === PROJECT_SELECT_NO_PLACEMENT_ORDER) {
        console.warn(
          'Project placement_order column missing — run migration 20250525140000_project_placement_order.sql',
        );
      } else if (
        selects[i] === PROJECT_SELECT_NO_CLIENT_INFO ||
        selects[i] === PROJECT_SELECT_NO_LABOR_ESTIMATES_NO_CLIENT
      ) {
        console.warn(
          'Project client_info column missing — run migration 20260530120000_project_client_info.sql',
        );
      }
      return result;
    }

    const msg = result.error.message ?? '';
    if (
      isJobsiteColumnError(msg) ||
      isClientInfoColumnError(msg) ||
      isTruckTicketsSchemaError(msg) ||
      isPlacementOrderColumnError(msg) ||
      isLaborEstimatesSchemaError(msg) ||
      isCustomEstimatesColumnError(msg)
    ) {
      if (isLaborEstimatesSchemaError(msg)) {
        console.warn(
          'labor_estimates table missing — run migration 20250526120000_labor_estimates_reinforcement_pricing.sql',
        );
      }
      if (isCustomEstimatesColumnError(msg)) {
        console.warn(
          'projects.custom_estimates column missing — run migration 20260606000000_project_custom_estimates.sql',
        );
      }
      continue;
    }
    return result;
  }

  return supabase
    .from('projects')
    .select(PROJECT_SELECT_LEGACY)
    .order('created_at', { ascending: false });
}

function selectAfterProjectWrite(): string {
  if (projectJobsiteColumnsAvailable === false) {
    return PROJECT_SELECT_NO_JOBSITE;
  }
  return PROJECT_SELECT;
}

async function fetchProjectById(projectId: string) {
  const selects = [
    PROJECT_SELECT,
    PROJECT_SELECT_NO_CLIENT_INFO,
    PROJECT_SELECT_NO_LABOR_ESTIMATES,
    PROJECT_SELECT_NO_LABOR_ESTIMATES_NO_CLIENT,
    PROJECT_SELECT_NO_PLACEMENT_ORDER,
    PROJECT_SELECT_NO_JOBSITE,
    PROJECT_SELECT_LEGACY,
  ];

  for (const select of selects) {
    const result = await supabase
      .from('projects')
      .select(select)
      .eq('id', projectId)
      .single();

    if (!result.error) {
      if (select === PROJECT_SELECT_NO_JOBSITE) {
        projectJobsiteColumnsAvailable = false;
      } else if (select === PROJECT_SELECT || select === PROJECT_SELECT_NO_LABOR_ESTIMATES) {
        projectJobsiteColumnsAvailable = true;
      }
      return result;
    }

    const msg = result.error.message ?? '';
    if (isRecoverableProjectSelectError(msg)) {
      if (isClientInfoColumnError(msg)) {
        console.warn(
          'Project client_info column missing — run migration 20260530120000_project_client_info.sql',
        );
      }
      if (isCustomEstimatesColumnError(msg)) {
        console.warn(
          'projects.custom_estimates column missing — run migration 20260606000000_project_custom_estimates.sql',
        );
      }
      continue;
    }
    return result;
  }

  return supabase
    .from('projects')
    .select(PROJECT_SELECT_LEGACY)
    .eq('id', projectId)
    .single();
}

async function fetchProjectByIdAfterInsert(projectId: string) {
  const selects = [
    PROJECT_SELECT_MINIMAL,
    PROJECT_SELECT_MINIMAL_NO_CLIENT_INFO,
    PROJECT_SELECT_MINIMAL_NO_CUSTOM_ESTIMATES,
    PROJECT_SELECT_MINIMAL_NO_CLIENT_NO_CUSTOM,
    PROJECT_SELECT_MINIMAL_NO_JOBSITE,
    PROJECT_SELECT_MINIMAL_LEGACY,
  ];

  for (const select of selects) {
    const result = await supabase
      .from('projects')
      .select(select)
      .eq('id', projectId)
      .single();

    if (!result.error) {
      if (select === PROJECT_SELECT_MINIMAL_NO_JOBSITE) {
        projectJobsiteColumnsAvailable = false;
      } else if (
        select === PROJECT_SELECT_MINIMAL ||
        select === PROJECT_SELECT_MINIMAL_NO_CLIENT_INFO
      ) {
        projectJobsiteColumnsAvailable = true;
      }
      return result;
    }

    const msg = result.error.message ?? '';
    if (isRecoverableProjectSelectError(msg)) {
      if (isClientInfoColumnError(msg)) {
        console.warn(
          'Project client_info column missing — run migration 20260530120000_project_client_info.sql',
        );
      }
      if (isCustomEstimatesColumnError(msg)) {
        console.warn(
          'projects.custom_estimates column missing — run migration 20260606000000_project_custom_estimates.sql',
        );
      }
      continue;
    }
    return result;
  }

  return supabase
    .from('projects')
    .select(PROJECT_SELECT_MINIMAL_LEGACY)
    .eq('id', projectId)
    .single();
}

type ProjectInsertSource = {
  name: string;
  description?: string;
  jobsiteAddress?: USAddress;
  clientInfo?: ProjectClientInfo;
  wasteFactor?: number;
  pourDate?: string | null;
};

function buildInsertFallbackRow(
  projectId: string,
  source: ProjectInsertSource,
  payload: Record<string, unknown>,
): Record<string, unknown> {
  const now = new Date().toISOString();
  const jobsite = jobsitePayload(source.jobsiteAddress);
  return {
    id: projectId,
    name: source.name,
    description: source.description ?? '',
    ...jobsite,
    client_info: payload.client_info ?? null,
    waste_factor: payload.waste_factor ?? source.wasteFactor ?? 10,
    pour_date: payload.pour_date ?? source.pourDate ?? null,
    mix_profile: payload.mix_profile ?? 'standard',
    created_at: now,
    updated_at: now,
    custom_estimates: null,
  };
}

async function insertProjectRow(
  payload: Record<string, unknown>,
  source: ProjectInsertSource,
) {
  let body = { ...payload };

  for (let attempt = 0; attempt < 8; attempt++) {
    const insertResult = await supabase.from('projects').insert(body).select('id').single();
    if (!insertResult.error) {
      const projectId = insertResult.data?.id as string | undefined;
      if (!projectId) {
        return {
          data: null,
          error: { message: 'Project created but no id was returned' },
        };
      }

      const fetchResult = await fetchProjectByIdAfterInsert(projectId);
      if (!fetchResult.error && fetchResult.data) {
        return fetchResult;
      }

      const fetchMsg = fetchResult.error?.message ?? '';
      if (fetchMsg) {
        console.warn('Project saved; reload after create failed:', fetchMsg);
      }
      return {
        data: buildInsertFallbackRow(projectId, source, body),
        error: null,
      };
    }

    const msg = insertResult.error.message ?? '';
    if (isClientInfoColumnError(msg)) {
      body = omitPayloadKeys(body, ['client_info']);
      console.warn(
        'Saved project without client_info — run migration 20260530120000_project_client_info.sql',
      );
      continue;
    }
    if (isJobsiteColumnError(msg)) {
      projectJobsiteColumnsAvailable = false;
      body = stripJobsiteFromPayload(body);
      console.warn(
        'Saved project without jobsite columns — apply migration 20250525130000_project_jobsite_address.sql',
      );
      continue;
    }
    if (isWasteFactorColumnError(msg)) {
      body = omitPayloadKeys(body, ['waste_factor']);
      continue;
    }
    if (isMixProfileColumnError(msg)) {
      body = omitPayloadKeys(body, ['mix_profile']);
      continue;
    }
    if (isPourDateColumnError(msg)) {
      body = omitPayloadKeys(body, ['pour_date']);
      continue;
    }

    return insertResult;
  }

  return {
    data: null,
    error: { message: 'Could not create project after multiple attempts' },
  };
}

async function updateProjectRow(
  projectId: string,
  payload: Record<string, unknown>,
) {
  const select = selectAfterProjectWrite();
  let result = await supabase
    .from('projects')
    .update(payload)
    .eq('id', projectId)
    .select(select)
    .single();

  if (result.error && isJobsiteColumnError(result.error.message ?? '')) {
    projectJobsiteColumnsAvailable = false;
    const withoutJobsite = omitPayloadKeys(payload, [
      'jobsite_street',
      'jobsite_street2',
      'jobsite_city',
      'jobsite_state',
      'jobsite_zip',
    ]);
    result = await supabase
      .from('projects')
      .update(withoutJobsite)
      .eq('id', projectId)
      .select(PROJECT_SELECT_NO_JOBSITE)
      .single();
  }

  if (result.error && isPlacementOrderColumnError(result.error.message ?? '')) {
    const withoutOrder = omitPayloadKeys(payload, ['placement_order']);
    console.warn(
      'Saved project without placement_order — apply migration 20250525140000_project_placement_order.sql',
    );
    result = await supabase
      .from('projects')
      .update(withoutOrder)
      .eq('id', projectId)
      .select(PROJECT_SELECT_NO_PLACEMENT_ORDER)
      .single();
  }

  if (result.error && isClientInfoColumnError(result.error.message ?? '')) {
    return fetchProjectById(projectId);
  }

  return result;
}

function mapJobsiteFromRow(row: {
  jobsite_street?: string | null;
  jobsite_street2?: string | null;
  jobsite_city?: string | null;
  jobsite_state?: string | null;
  jobsite_zip?: string | null;
}): USAddress | undefined {
  const addr: USAddress = {
    ...EMPTY_US_ADDRESS,
    street: row.jobsite_street?.trim() ?? '',
    street2: row.jobsite_street2?.trim() ?? '',
    city: row.jobsite_city?.trim() ?? '',
    state: row.jobsite_state?.trim() ?? '',
    zip: row.jobsite_zip?.trim() ?? '',
  };
  if (!addr.city && !addr.state && !addr.zip && !addr.street) return undefined;
  return addr;
}

function jobsitePayload(addr?: USAddress) {
  if (!addr) return {};
  return {
    jobsite_street: addr.street?.trim() ?? '',
    jobsite_street2: addr.street2?.trim() ?? '',
    jobsite_city: addr.city?.trim() ?? '',
    jobsite_state: addr.state?.trim() ?? '',
    jobsite_zip: addr.zip?.trim() ?? '',
  };
}

function mapProjectFromRow(row: any): Project {
  const qcRecords = (row.qc_records || []).map(mapQcRecordFromDb);
  const truckTicketsFromDb = (row.truck_tickets || []).map(mapTruckTicketFromDb);
  return {
    id: row.id,
    name: row.name,
    description: row.description,
    jobsiteAddress: mapJobsiteFromRow(row),
    clientInfo: parseClientInfoFromDb(row.client_info),
    wasteFactor: row.waste_factor,
    createdAt: row.created_at,
    updatedAt: row.updated_at,
    pourDate: row.pour_date,
    placementOrder: parsePlacementOrder(row.placement_order),
    mixProfile: (row.mix_profile as MixProfileType) || 'standard',
    calculations: (row.calculations || []).map(mapCalculationFromDb),
    reinforcements: (row.reinforcement_sets || []).map(mapReinforcementSetFromDb),
    laborEstimates: (row.labor_estimates || []).map(mapLaborEstimateFromDb),
    qcRecords: qcRecords.filter((r: QCRecord) => !isTruckTicketRecord(r)),
    truckTickets: mergeTruckTicketsForProject(qcRecords, truckTicketsFromDb),
    approvedChangeOrderTotal:
      row.approved_change_order_total != null
        ? Number(row.approved_change_order_total)
        : undefined,
    baseContractValue:
      row.base_contract_value != null ? Number(row.base_contract_value) : undefined,
    currentContractValue:
      row.current_contract_value != null ? Number(row.current_contract_value) : undefined,
    customEstimates: parseCustomEstimatesFromDb(row.custom_estimates),
  };
}

