    doc.text('Mix Design Requirements', 14, 50);
    
    doc.setFontSize(12);
    doc.text(`Design Strength: ${psi} PSI`, 14, 65);
    doc.text(`Air Content Range: ${airContent[0]}-${airContent[1]}%`, 14, 75);
    doc.text(`Maximum W/C Ratio: ${waterCementRatio.toFixed(2)}`, 14, 85);
    
    // Admixtures table
    doc.setFontSize(14);
