      doc.setLineWidth(0.5);
      doc.setDrawColor(209, 213, 219);
      // Create dashed line effect with short segments
      const dashLength = 3;
      const gapLength = 3;
      let currentX = margin;
      while (currentX < pageWidth - margin) {
        const endX = Math.min(currentX + dashLength, pageWidth - margin);
        doc.line(currentX, yPosition, endX, yPosition);
        currentX += dashLength + gapLength;
      }
      yPosition += 15;
      
      // Footer - centered
      checkPageBreak(20);
      doc.setFontSize(10);
      doc.setFont('helvetica', 'normal');
      doc.setTextColor(107, 114, 128);
      doc.text('Prepared by:', pageWidth / 2, yPosition, { align: 'center' });
      yPosition += 8;
      
      doc.setFont('helvetica', 'bold');
      doc.setTextColor(31, 41, 55);
      doc.text(extractedData.preparedBy || 'Prepared By Name', pageWidth / 2, yPosition, { align: 'center' });
      
      if (extractedData.preparedByTitle) {
        yPosition += 8;
        doc.setFontSize(9);
        doc.setFont('helvetica', 'normal');
        doc.setTextColor(107, 114, 128);
        doc.text(extractedData.preparedByTitle, pageWidth / 2, yPosition, { align: 'center' });
      }
    }
    
    // Generate Minimal Template Layout
    else if (templateType === 'minimal') {
      // Simple header
      doc.setFontSize(18);
      doc.setFont('helvetica', 'bold');
      doc.text(extractedData.businessName || 'Business Name', margin, yPosition);
      yPosition += 8;
      
      // Business slogan
      if (extractedData.businessSlogan) {
        doc.setFontSize(10);
        doc.setFont('helvetica', 'italic');
        doc.setTextColor(107, 114, 128);
        doc.text(extractedData.businessSlogan, margin, yPosition);
        yPosition += 6;
      }
      
      // Business address
      if (extractedData.businessAddress) {
        doc.setFontSize(9);
        doc.setFont('helvetica', 'normal');
        doc.setTextColor(107, 114, 128);
        doc.text(extractedData.businessAddress, margin, yPosition);
        yPosition += 5;
      }
      
      // Contact info in one line
      doc.setFontSize(9);
      doc.setTextColor(107, 114, 128);
      const contactInfo = [];
      if (extractedData.businessPhone) contactInfo.push(extractedData.businessPhone);
      if (extractedData.businessEmail) contactInfo.push(extractedData.businessEmail);
      if (extractedData.businessLicenseNumber) contactInfo.push(`License: ${extractedData.businessLicenseNumber}`);
      
      if (contactInfo.length > 0) {
        doc.text(contactInfo.join('   •   '), margin, yPosition);
        yPosition += 15;
      } else {
        yPosition += 10;
      }
      
      // Client & Project section
      doc.setFontSize(14);
      doc.setFont('helvetica', 'bold');
      doc.setTextColor(0, 0, 0);
      doc.text('Proposal For', margin, yPosition);
      yPosition += 10;
      
      doc.setFontSize(12);
      doc.setFont('helvetica', 'bold');
      doc.text(extractedData.clientName || 'Client Name', margin, yPosition);
      yPosition += 8;
      
      doc.setFontSize(11);
      doc.setFont('helvetica', 'bold');
      doc.text(extractedData.projectTitle || 'Project Title', margin, yPosition);
      yPosition += 6;
      
      doc.setFontSize(9);
      doc.setFont('helvetica', 'normal');
      doc.setTextColor(107, 114, 128);
      doc.text(extractedData.date, margin, yPosition);
      yPosition += 15;
      
      // Horizontal line
      doc.setLineWidth(0.5);
      doc.setDrawColor(209, 213, 219);
      doc.line(margin, yPosition, pageWidth - margin, yPosition);
      yPosition += 15;
      
      // Introduction
      if (extractedData.introduction) {
        doc.setFontSize(11);
        doc.setFont('helvetica', 'bold');
        doc.setTextColor(0, 0, 0);
        doc.text('Introduction', margin, yPosition);
        yPosition += 8;
        
        doc.setFontSize(10);
        doc.setFont('helvetica', 'normal');
        addText(extractedData.introduction, 10, false);
        yPosition += 5;
      }
      
      // Scope of Work
      if (extractedData.scope) {
        doc.setFontSize(11);
        doc.setFont('helvetica', 'bold');
        doc.setTextColor(0, 0, 0);
        doc.text('Scope of Work', margin, yPosition);
        yPosition += 8;
        
        doc.setFontSize(10);
        doc.setFont('helvetica', 'normal');
        addText(extractedData.scope, 10, false);
        yPosition += 5;
      }
      
      // Timeline Inline
      if (timelineTable.length > 1) {
        checkPageBreak(25);
        doc.setFontSize(11);
        doc.setFont('helvetica', 'bold');
        doc.setTextColor(0, 0, 0);
        doc.text('Timeline', margin, yPosition);
        yPosition += 10;
        
        doc.setFontSize(10);
        doc.setFont('helvetica', 'normal');
        
        for (let i = 1; i < timelineTable.length; i++) {
          const row = timelineTable[i];
          if (row.length >= 3 && row[0].trim()) {
            checkPageBreak(12);
            
            // Phase name on left
            doc.setTextColor(0, 0, 0);
            doc.text(row[0], margin, yPosition);
            
            // Date range on right
            doc.setFont('helvetica', 'bold');
            const dateRange = `${row[1]} – ${row[2]}`;
            doc.text(dateRange, pageWidth - margin, yPosition, { align: 'right' });
            
            doc.setFont('helvetica', 'normal');
            yPosition += 10;
          }
        }
        yPosition += 5;
      }
      
      // Pricing Inline
      if (pricingTable.length > 1) {
        checkPageBreak(25);
        doc.setFontSize(11);
        doc.setFont('helvetica', 'bold');
        doc.setTextColor(0, 0, 0);
        doc.text('Pricing', margin, yPosition);
        yPosition += 10;
        
        doc.setFontSize(10);
        doc.setFont('helvetica', 'normal');
        
        for (let i = 1; i < pricingTable.length; i++) {
          const row = pricingTable[i];
          if (row.length >= 2 && row[0].trim()) {
            checkPageBreak(12);
            
            // Description on left
            doc.setTextColor(0, 0, 0);
            const descLines = doc.splitTextToSize(row[0], pageWidth - margin - 60);
            doc.text(descLines[0], margin, yPosition);
            
            // Amount on right
            doc.setFont('helvetica', 'bold');
            doc.text(row[1], pageWidth - margin, yPosition, { align: 'right' });
            
            doc.setFont('helvetica', 'normal');
            yPosition += 10;
          }
        }
        yPosition += 5;
      }
      
      // Terms & Conditions
      if (extractedData.terms) {
        checkPageBreak(25);
        doc.setFontSize(11);
        doc.setFont('helvetica', 'bold');
        doc.setTextColor(0, 0, 0);
        doc.text('Terms & Conditions', margin, yPosition);
        yPosition += 8;
        
        doc.setFontSize(9);
        doc.setFont('helvetica', 'normal');
        addText(extractedData.terms, 9, false);
        yPosition += 10;
      }
      
      // Footer with border
      checkPageBreak(20);
      doc.setLineWidth(0.5);
      doc.setDrawColor(229, 231, 235);
      doc.line(margin, yPosition, pageWidth - margin, yPosition);
      yPosition += 12;
      
      doc.setFontSize(10);
      doc.setFont('helvetica', 'normal');
      doc.setTextColor(107, 114, 128);
      doc.text('Prepared by:', margin, yPosition);
      yPosition += 8;
      
      doc.setFont('helvetica', 'bold');
      doc.setTextColor(0, 0, 0);
      doc.text(extractedData.preparedBy || 'Prepared By Name', margin, yPosition);
    }
    
    // Fallback for unrecognized template types
    else {
      console.warn(`Unknown template type: ${templateType}, using classic layout`);
      
      // Use classic template as fallback
      doc.setFontSize(18);
      doc.setFont('helvetica', 'bold');
      doc.text(extractedData.businessName || 'Business Name', margin, yPosition);
      
      doc.text('Proposal', pageWidth - margin, yPosition, { align: 'right' });
      yPosition += 20;
      
      doc.setFontSize(14);
      doc.text('Prepared For:', margin, yPosition);
      yPosition += 10;
      
      doc.setFontSize(12);
      doc.text(extractedData.clientName || 'Client Name', margin, yPosition);
      yPosition += 15;
      
      doc.setFontSize(16);
      doc.text(extractedData.projectTitle || 'Project Title', margin, yPosition);
      yPosition += 15;
      
      if (extractedData.introduction) {
        addText(extractedData.introduction, 11, false);
      }
      
      if (extractedData.scope) {
        doc.setFontSize(14);
        doc.setFont('helvetica', 'bold');
        doc.text('Scope of Work', margin, yPosition);
        yPosition += 10;
        addText(extractedData.scope, 11, false);
      }
    }
    
    // Ensure the PDF has content before saving
    if (yPosition <= margin + 20) {
      // PDF appears to be empty, add some basic content
      console.warn('PDF appears empty, adding fallback content');
      doc.setFontSize(16);
      doc.setFont('helvetica', 'bold');
      doc.text('Concrete Proposal', pageWidth / 2, 40, { align: 'center' });
      
      doc.setFontSize(12);
      doc.setFont('helvetica', 'normal');
      doc.text(`Generated: ${format(new Date(), 'MMMM d, yyyy')}`, pageWidth / 2, 60, { align: 'center' });
      
      doc.text('This proposal was generated electronically.', margin, 100);
      doc.text('Please contact us for detailed information.', margin, 120);
    }
  
  // Save the PDF
    const pdfFilename = filename || `proposal-${templateType}-${Date.now()}.pdf`;
    await savePDFWithPlatformSupport(doc, pdfFilename, title);
  } catch (error) {
    console.error('Error generating proposal PDF:', error);
    throw error;
  }
}

export async function generateProjectPDF(
  project: Project, 
  selectedPsi: keyof typeof CONCRETE_MIX_DESIGNS
): Promise<void> {
  try {
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.width;
  
  // Header
  doc.setFontSize(24);
  doc.text('Project Report', pageWidth / 2, 20, { align: 'center' });
  
  // Project Details
  doc.setFontSize(14);
  doc.text('Project Details', 14, 40);
  doc.setFontSize(12);
  doc.text(`Name: ${project.name || 'Untitled Project'}`, 14, 50);
  doc.text(`Created: ${formatDateSafely(project.createdAt)}`, 14, 60);
  if (project.description) {
    doc.text('Description:', 14, 70);
    const splitDescription = doc.splitTextToSize(project.description, pageWidth - 28);
    doc.text(splitDescription, 14, 80);
  }
  
  // Calculate total volume
  const calculations = project.calculations || [];
  const totalVolume = calculations.reduce((total, calc) => total + (calc.result?.volume || 0), 0);
  
  // Mix Design
  const mixDesign = calculateMixMaterials(totalVolume || 1, selectedPsi);
  doc.setFontSize(14);
  doc.text('Concrete Mix Design', 14, 110);
  doc.setFontSize(12);
  
  const mixDesignData = [
    ['Component', 'Amount', 'Unit'],
    ['Portland Cement', mixDesign.materials.cement.toFixed(2), 'yd³'],
    ['Fine Aggregate (Sand)', mixDesign.materials.sand.toFixed(2), 'yd³'],
    ['Coarse Aggregate', mixDesign.materials.aggregate.toFixed(2), 'yd³'],
    ['Water', mixDesign.materials.water.toString(), 'gal'],
  ];
  
    doc.autoTable({
    startY: 120,
    head: [mixDesignData[0]],
    body: mixDesignData.slice(1),
    theme: 'striped',
    headStyles: { fillColor: [59, 130, 246] },
  });
  
  // Additional Mix Design Details
    const currentY = doc.lastAutoTable.finalY + 10;
  doc.text(`Strength: ${selectedPsi} PSI`, 14, currentY);
  doc.text(`Water/Cement Ratio: ${mixDesign.waterCementRatio}`, 14, currentY + 10);
  doc.text(`Slump Range: ${mixDesign.slump.min}" - ${mixDesign.slump.max}"`, 14, currentY + 20);
  
  // Cost Estimate
  const costEstimate = calculateConcreteCost(totalVolume || 1, selectedPsi);
  doc.setFontSize(14);
  doc.text('Cost Estimate', 14, currentY + 40);
  
  const costData = [
    ['Item', 'Cost'],
    ['Concrete Cost', formatPrice(costEstimate.concreteCost)],
    ['Delivery Fees', formatPrice(costEstimate.deliveryFees.totalDeliveryFees)],
    ['Total Estimated Cost', formatPrice(costEstimate.totalCost)]
  ];
  
    doc.autoTable({
    startY: currentY + 50,
    head: [costData[0]],
    body: costData.slice(1),
    theme: 'striped',
    headStyles: { fillColor: [59, 130, 246] },
  });

  // QC Records - only if they exist in the project
  const projectWithQC = project as any;
  if (projectWithQC.qcRecords && projectWithQC.qcRecords.length > 0) {
      const qcY = doc.lastAutoTable.finalY + 20;
    doc.setFontSize(14);
    doc.text('Quality Control Records', 14, qcY);

    const qcData = projectWithQC.qcRecords.map((record: any) => [
      format(new Date(record.date), 'MM/dd/yyyy'),
      `${record.temperature}°F`,
      `${record.humidity}%`,
      `${record.slump}"`,
      `${record.air_content}%`,
      record.cylindersMade.toString(),
      record.notes || ''
    ]);

      doc.autoTable({
      startY: qcY + 10,
      head: [['Date', 'Temp', 'Humidity', 'Slump', 'Air', 'Cylinders', 'Notes']],
      body: qcData,
      theme: 'striped',
      headStyles: { fillColor: [59, 130, 246] },
      columnStyles: {
        0: { cellWidth: 25 },
        1: { cellWidth: 20 },
        2: { cellWidth: 20 },
        3: { cellWidth: 20 },
        4: { cellWidth: 20 },
        5: { cellWidth: 20 },
        6: { cellWidth: 'auto' }
      }
    });
  }
  
  // Calculations Table
  if (calculations.length > 0) {
      const calculationsY = doc.lastAutoTable.finalY + 20;
    doc.setFontSize(14);
    doc.text('Calculations', 14, calculationsY);
    
    const calculationsData = calculations.map(calc => [
      calc.type.charAt(0).toUpperCase() + calc.type.slice(1),
      formatDateSafely(calc.createdAt),
      `${calc.result?.volume || 0} yd³`,
      calc.result?.bags?.toString() || '0'
    ]);
    
      doc.autoTable({
      startY: calculationsY + 10,
      head: [['Type', 'Date', 'Volume', 'Bags Required']],
      body: calculationsData,
      theme: 'striped',
      headStyles: { fillColor: [59, 130, 246] },
    });
  }
  
  // Footer
  const pageCount = (doc.internal as any).getNumberOfPages();
  doc.setFontSize(10);
  for (let i = 1; i <= pageCount; i++) {
    doc.setPage(i);
    doc.text(
      `Page ${i} of ${pageCount}`,
      pageWidth / 2,
      doc.internal.pageSize.height - 10,
      { align: 'center' }
    );
  }
  
    // Save the PDF with platform support
  const fileName = project.name ? 
    `${project.name.toLowerCase().replace(/\s+/g, '-')}-report.pdf` : 
    'concrete-mix-report.pdf';
    
    await savePDFWithPlatformSupport(doc, fileName, `Project Report - ${project.name || 'Untitled'}`);
  } catch (error) {
    console.error('Error generating project PDF:', error);
    throw error;
  }
}

export async function generateReinforcementPDF(
  result: any,
  options: {
    projectName: string;
    calculatorData: any;
    coverIn: number;
    mode: string;
    isColumn: boolean;
    spacingXIn?: number;
    spacingYIn?: number;
    verticalBars?: number;
  },
  title: string,
  filename?: string
): Promise<void> {
  try {
    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.width;
    const pageHeight = doc.internal.pageSize.height;
    const margin = 20;
    let yPosition = margin;

    // Helper function to check page break
    const checkPageBreak = (requiredSpace: number = 15) => {
      if (yPosition + requiredSpace > pageHeight - margin) {
        doc.addPage();
        yPosition = margin;
      }
    };

    // Header
    doc.setFontSize(20);
    doc.setFont('helvetica', 'bold');
    doc.text('Reinforcement Design Report', pageWidth / 2, yPosition, { align: 'center' });
    yPosition += 15;

    doc.setFontSize(12);
    doc.setFont('helvetica', 'normal');
    doc.text(`Generated: ${format(new Date(), 'MMMM d, yyyy')}`, pageWidth / 2, yPosition, { align: 'center' });
    yPosition += 20;

    // Project Information
    doc.setFontSize(16);
    doc.setFont('helvetica', 'bold');
    doc.text('Project Information', margin, yPosition);
    yPosition += 10;

    doc.setFontSize(12);
    doc.setFont('helvetica', 'normal');
    doc.text(`Project: ${options.projectName}`, margin, yPosition);
    yPosition += 8;
    doc.text(`Reinforcement Type: ${options.mode.charAt(0).toUpperCase() + options.mode.slice(1)}`, margin, yPosition);
    yPosition += 8;
    doc.text(`Structure Type: ${options.isColumn ? 'Column' : 'Slab'}`, margin, yPosition);
    yPosition += 15;

    // Dimensions
    doc.setFontSize(16);
    doc.setFont('helvetica', 'bold');
    doc.text('Dimensions', margin, yPosition);
    yPosition += 10;

    doc.setFontSize(12);
    doc.setFont('helvetica', 'normal');
    doc.text(`Length: ${options.calculatorData.length_ft}'`, margin, yPosition);
    yPosition += 8;
    doc.text(`Width: ${options.calculatorData.width_ft}'`, margin, yPosition);
    yPosition += 8;
    doc.text(`Thickness: ${options.calculatorData.thickness_in}"`, margin, yPosition);
    yPosition += 8;
    if (options.calculatorData.height_ft) {
      doc.text(`Height: ${options.calculatorData.height_ft}'`, margin, yPosition);
      yPosition += 8;
    }
    doc.text(`Cover: ${options.coverIn}"`, margin, yPosition);
    yPosition += 15;

    // Design Results
    checkPageBreak(30);
    doc.setFontSize(16);
    doc.setFont('helvetica', 'bold');
    doc.text('Design Results', margin, yPosition);
    yPosition += 10;

    if (options.mode === 'rebar') {
      doc.setFontSize(12);
      doc.setFont('helvetica', 'normal');
      
      if (result.pick) {
        doc.text(`Recommended Bar Size: ${result.pick.size}`, margin, yPosition);
        yPosition += 8;
        
        if (options.isColumn) {
          doc.text(`Vertical Bars: ${result.pick.verticalBars || options.verticalBars}`, margin, yPosition);
          yPosition += 8;
        } else {
          doc.text(`X-Direction Spacing: ${result.pick.spacingXIn || options.spacingXIn}"`, margin, yPosition);
          yPosition += 8;
          doc.text(`Y-Direction Spacing: ${result.pick.spacingYIn || options.spacingYIn}"`, margin, yPosition);
          yPosition += 8;
        }
      }
      
      if (result.totalBars) {
        doc.text(`Total Bars: ${result.totalBars}`, margin, yPosition);
        yPosition += 8;
      }
      
      if (result.totalLinearFt) {
        doc.text(`Total Linear Feet: ${result.totalLinearFt.toFixed(1)} ft`, margin, yPosition);
        yPosition += 15;
      }

      // Cut List Table
      if (result.listX || result.listY || result.verticalBars) {
        checkPageBreak(40);
        doc.setFontSize(14);
        doc.setFont('helvetica', 'bold');
        doc.text('Cut List', margin, yPosition);
        yPosition += 10;

        const tableData: string[][] = [];
        
        if (options.isColumn) {
          // Column rebar tables
          if (result.verticalBars) {
            tableData.push(['Type', 'Length', 'Quantity']);
            result.verticalBars.forEach((item: any) => {
              tableData.push(['Vertical Bar', `${item.lengthFt.toFixed(1)}'`, item.qty.toString()]);
            });
          }
          if (result.tieList) {
            result.tieList.forEach((item: any) => {
              tableData.push(['Tie Bar', `${item.lengthFt.toFixed(1)}'`, item.qty.toString()]);
            });
          }
        } else {
          // Slab rebar tables
          tableData.push(['Direction', 'Length', 'Quantity']);
          
          if (result.listX) {
            result.listX.forEach((item: any) => {
              tableData.push(['X-Direction', `${item.lengthFt.toFixed(1)}'`, item.qty.toString()]);
            });
          }
          
          if (result.listY) {
            result.listY.forEach((item: any) => {
              tableData.push(['Y-Direction', `${item.lengthFt.toFixed(1)}'`, item.qty.toString()]);
            });
          }
        }

        if (tableData.length > 1) {
          doc.autoTable({
            startY: yPosition,
            head: [tableData[0]],
            body: tableData.slice(1),
            theme: 'grid',
            headStyles: { 
              fillColor: [59, 130, 246],
              textColor: [255, 255, 255],
              fontSize: 12,
              fontStyle: 'bold'
            },
            bodyStyles: {
              fontSize: 11,
              textColor: [60, 60, 60]
            },
            margin: { left: margin, right: margin },
          });
          yPosition = doc.lastAutoTable.finalY + 15;
        }
      }
    }

    // Notes and References
    checkPageBreak(40);
    doc.setFontSize(14);
    doc.setFont('helvetica', 'bold');
    doc.text('Notes', margin, yPosition);
    yPosition += 10;

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    const notes = [
      '• This design is for reference purposes only',
      '• Consult a structural engineer for final approval',
      '• All dimensions and spacing should be verified on-site',
      '• Follow local building codes and ACI standards',
      '• Ensure proper concrete cover for environmental conditions'
    ];

    notes.forEach(note => {
      doc.text(note, margin, yPosition);
      yPosition += 6;
    });

    // Footer
    yPosition += 10;
    doc.setFontSize(8);
    doc.setTextColor(128, 128, 128);
    doc.text('Generated by Concrete Calculator App', pageWidth / 2, pageHeight - 10, { align: 'center' });

    // Save the PDF
    const pdfFilename = filename || `reinforcement-design-${Date.now()}.pdf`;
    await savePDFWithPlatformSupport(doc, pdfFilename, title);
  } catch (error) {
    console.error('Error generating reinforcement PDF:', error);
    throw error;
  }
}

import type { TrackedProposalRow, ProposalStatus } from '../types/proposalTracking';
import { PROPOSAL_PIPELINE_STATUSES } from '../types/proposalTracking';

export type ProposalPipelineCounts = Record<ProposalStatus, number>;

export type ProposalPipelineRevenue = Record<ProposalStatus, number>;

export interface ProposalFinancialKpis {
  /** Sent / viewed / opened — awaiting client decision */
  pendingRevenue: number;
  /** All open deals except declined & paid */
  openPipelineRevenue: number;
  /** Probability-weighted open pipeline (matches CRM) */
  weightedForecast: number;
  acceptedRevenue: number;
  monthlyRevenue: number;
  averageJobSize: number;
  winRate: number;
  laborCostTotal: number;
  materialCostTotal: number;
  grossProfit: number;
  acceptedCount: number;
  declinedCount: number;
  /** Rolled up from projects.current_contract_value */
  currentContractValue: number;
  /** Rolled up from projects.approved_change_order_total */
  approvedChangeOrderTotal: number;
  /** Change orders sent / viewed (client has not accepted yet) */
  changeOrderPendingRevenue: number;
  /** Sum of accepted change order totals (from CO records) */
  changeOrderAcceptedRevenue: number;
  /** Probability-weighted open change orders */
  changeOrderWeightedForecast: number;
}

export interface ProposalDashboardMetrics {
  pipeline: ProposalPipelineCounts;
  pipelineRevenue: ProposalPipelineRevenue;
  financial: ProposalFinancialKpis;
}

const PENDING_STATUSES: ProposalStatus[] = ['sent', 'viewed', 'opened'];
const WON_STATUSES: ProposalStatus[] = ['accepted', 'deposit_paid', 'scheduled', 'paid'];

const WEIGHT_BY_STATUS: Record<ProposalStatus, number> = {
  draft: 0.1,
  sent: 0.25,
  viewed: 0.5,
  opened: 0.5,
  accepted: 1,
  declined: 0,
  deposit_paid: 1,
  scheduled: 1,
  paid: 1,
};

function isOpenPipeline(status: ProposalStatus): boolean {
  return status !== 'declined' && status !== 'paid';
}

function num(v: number | string | null | undefined): number {
  if (v == null) return 0;
  const n = typeof v === 'number' ? v : parseFloat(String(v));
  return Number.isFinite(n) ? n : 0;
}

function isPending(status: ProposalStatus): boolean {
  return PENDING_STATUSES.includes(status);
}

function isWon(status: ProposalStatus): boolean {
  return WON_STATUSES.includes(status);
}

function wonAt(p: TrackedProposalRow): string | null {
  // Use the most meaningful "won" timestamp available for monthly rollups.
  // Fall back to updated_at if we have no stage timestamp (older rows).
  return (
    (p.paid_at as any) ??
    p.scheduled_at ??
    p.deposit_paid_at ??
    p.accepted_at ??
    p.updated_at ??
    null
  );
}

export function buildProposalPipelineCounts(
  proposals: TrackedProposalRow[],
): ProposalPipelineCounts {
  const counts = Object.fromEntries(
    PROPOSAL_PIPELINE_STATUSES.map((s) => [s, 0]),
  ) as ProposalPipelineCounts;

  for (const p of proposals) {
    const status = p.status ?? 'draft';
    if (status in counts) counts[status as ProposalStatus] += 1;
    else counts.draft += 1;
  }

  return counts;
}

export function buildProposalPipelineRevenue(
  proposals: TrackedProposalRow[],
): ProposalPipelineRevenue {
  const revenue = Object.fromEntries(
    PROPOSAL_PIPELINE_STATUSES.map((s) => [s, 0]),
  ) as ProposalPipelineRevenue;

  for (const p of proposals) {
    const status = (p.status ?? 'draft') as ProposalStatus;
    const amount = num(p.total_amount);
    if (status in revenue) revenue[status as ProposalStatus] += amount;
    else revenue.draft += amount;
  }

  return revenue;
}

export function buildProposalFinancialKpis(
  proposals: TrackedProposalRow[],
  now = new Date(),
): ProposalFinancialKpis {
  const wonProposals = proposals.filter((p) => isWon(p.status));
  const pendingProposals = proposals.filter((p) => isPending(p.status));
  const declinedProposals = proposals.filter((p) => p.status === 'declined');

  const wonCount = wonProposals.length;
  const declinedCount = declinedProposals.length;
  const sentCount = wonCount + declinedCount + pendingProposals.length;

  const totalRevenue = wonProposals.reduce(
    (sum, p) => sum + num(p.total_amount),
    0,
  );

  const pendingRevenue = pendingProposals.reduce(
    (sum, p) => sum + num(p.total_amount),
    0,
  );

  const openProposals = proposals.filter((p) => isOpenPipeline(p.status ?? 'draft'));
  const openPipelineRevenue = openProposals.reduce(
    (sum, p) => sum + num(p.total_amount),
    0,
  );
  const weightedForecast = openProposals.reduce((sum, p) => {
    const status = (p.status ?? 'draft') as ProposalStatus;
    return sum + num(p.total_amount) * (WEIGHT_BY_STATUS[status] ?? 0);
  }, 0);

  const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);
  const monthlyRevenue = wonProposals
    .filter((p) => {
      const at = wonAt(p);
      return at ? new Date(at) >= monthStart : false;
    })
    .reduce((sum, p) => sum + num(p.total_amount), 0);

  // Win rate = won / sent (excluding drafts)
  const winRate = sentCount > 0 ? wonCount / sentCount : 0;

  const averageJobSize = wonCount > 0 ? totalRevenue / wonCount : 0;

  // Costs should be compared to revenue for the same cohort (won).
  const laborCostTotal = wonProposals.reduce(
    (sum, p) => sum + num(p.labor_cost),
    0,
  );
  const materialCostTotal = wonProposals.reduce(
    (sum, p) => sum + num(p.material_cost),
    0,
  );

  const storedGrossProfit = wonProposals.reduce(
    (sum, p) => sum + num(p.gross_profit),
    0,
  );
  const grossProfit =
    storedGrossProfit > 0
      ? storedGrossProfit
      : totalRevenue - laborCostTotal - materialCostTotal;

  return {
    pendingRevenue,
    openPipelineRevenue,
    weightedForecast,
    acceptedRevenue: totalRevenue,
    monthlyRevenue,
    averageJobSize,
    winRate,
    laborCostTotal,
    materialCostTotal,
    grossProfit,
    acceptedCount: wonCount,
    declinedCount,
    currentContractValue: 0,
    approvedChangeOrderTotal: 0,
    changeOrderPendingRevenue: 0,
    changeOrderAcceptedRevenue: 0,
    changeOrderWeightedForecast: 0,
  };
}

export function mergeProjectContractRollup(
  financial: ProposalFinancialKpis,
  projects: { currentContractValue?: number; approvedChangeOrderTotal?: number }[],
): ProposalFinancialKpis {
  let currentContractValue = 0;
  let approvedChangeOrderTotal = 0;
  for (const p of projects) {
    currentContractValue += num(p.currentContractValue);
    approvedChangeOrderTotal += num(p.approvedChangeOrderTotal);
  }
  return { ...financial, currentContractValue, approvedChangeOrderTotal };
}

export function buildProposalDashboardMetrics(
  proposals: TrackedProposalRow[],
  now = new Date(),
): ProposalDashboardMetrics {
  return {
    pipeline: buildProposalPipelineCounts(proposals),
    pipelineRevenue: buildProposalPipelineRevenue(proposals),
    financial: buildProposalFinancialKpis(proposals, now),
  };
}

export function formatProposalMoney(n: number): string {
  return n.toLocaleString(undefined, {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0,
  });
}

export function formatWinRate(rate: number): string {
  return `${Math.round(rate * 100)}%`;
}

import type { QCRecord, QCRecordType } from '../types';

export function computeBreakResult(
  testAgeDays?: number,
  designStrengthPsi?: number,
  breakStrengthPsi?: number,
  userChoice?: 'pass' | 'fail' | 'informational',
): 'pass' | 'fail' | 'informational' | undefined {
  if (userChoice) return userChoice;
  if (designStrengthPsi == null || breakStrengthPsi == null) return undefined;
  if (breakStrengthPsi >= designStrengthPsi) return 'pass';
  if (testAgeDays === 7 || testAgeDays === 14) return 'informational';
  return 'fail';
}

function numOrUndefined(v: unknown): number | undefined {
  if (v == null || v === '') return undefined;
  const n = Number(v);
  return Number.isFinite(n) ? n : undefined;
}

export function isQcRecordTypeColumnError(message: string): boolean {
  const m = message.toLowerCase();
  return m.includes('record_type') || m.includes('record_data');
}

export function buildRecordDataPayload(rec: Partial<QCRecord>): Record<string, unknown> {
  const payload: Record<string, unknown> = {};
  const copy = (key: keyof QCRecord, value: unknown) => {
    if (value !== undefined && value !== null && value !== '') {
      payload[key] = value;
    }
  };

  copy('recordType', rec.recordType);
  copy('windSpeed', rec.windSpeed);
  copy('concreteTemperature', rec.concreteTemperature);
  copy('unitWeight', rec.unitWeight);
  copy('truckNumber', rec.truckNumber);
  copy('ticketNumber', rec.ticketNumber);
  copy('batchTime', rec.batchTime);
  copy('sampleTime', rec.sampleTime);
  copy('testAgeDays', rec.testAgeDays);
  copy('cylinderId', rec.cylinderId);
  copy('breakDate', rec.breakDate);
  copy('designStrengthPsi', rec.designStrengthPsi);
  copy('breakStrengthPsi', rec.breakStrengthPsi);
  copy('loadLbs', rec.loadLbs);
  copy('averageStrengthPsi', rec.averageStrengthPsi);
  copy('breakResult', rec.breakResult);
  copy('temperature', rec.temperature);
  copy('humidity', rec.humidity);
  copy('slump', rec.slump);
  copy('airContent', rec.airContent);
  copy('cylindersMade', rec.cylindersMade);

  return payload;
}

export function legacyQcColumns(rec: Partial<QCRecord>) {
  return {
    temperature: rec.temperature ?? 0,
    humidity: rec.humidity ?? 0,
    slump: rec.slump ?? 0,
    air_content: rec.airContent ?? 0,
    cylinders_made: rec.cylindersMade ?? 0,
  };
}

export function buildQcInsertRow(
  projectId: string,
  rec: Omit<QCRecord, 'id' | 'projectId' | 'createdAt' | 'updatedAt'>,
) {
  const recordType: QCRecordType = rec.recordType ?? 'fresh_test';
  return {
    project_id: projectId,
    date: rec.date,
    record_type: recordType,
    record_data: buildRecordDataPayload({ ...rec, recordType }),
    notes: rec.notes ?? '',
    ...legacyQcColumns(rec),
  };
}

export function buildQcUpdateRow(rec: Partial<QCRecord>) {
  const recordType = rec.recordType;
  const row: Record<string, unknown> = {
    updated_at: new Date().toISOString(),
  };

  if (rec.date !== undefined) row.date = rec.date;
  if (rec.notes !== undefined) row.notes = rec.notes ?? '';
  if (recordType !== undefined) row.record_type = recordType;

  const hasLegacy =
    rec.temperature !== undefined ||
    rec.humidity !== undefined ||
    rec.slump !== undefined ||
    rec.airContent !== undefined ||
    rec.cylindersMade !== undefined;

  if (hasLegacy) {
    Object.assign(row, legacyQcColumns(rec));
  }

  const dataPayload = buildRecordDataPayload(rec);
  if (Object.keys(dataPayload).length > 0) {
    row.record_data = dataPayload;
  }

  return row;
}

export function mapQcRecordFieldsFromDb(r: any): Omit<QCRecord, 'id' | 'projectId' | 'createdAt' | 'updatedAt' | 'checklist'> {
  const data = r.record_data ?? {};
  const recordType: QCRecordType =
    r.record_type ?? data.recordType ?? 'fresh_test';

  return {
    recordType,
    date: r.date,
    temperature: numOrUndefined(r.temperature ?? data.temperature),
    humidity: numOrUndefined(r.humidity ?? data.humidity),
    windSpeed: numOrUndefined(data.windSpeed),
    concreteTemperature: numOrUndefined(data.concreteTemperature),
    slump: numOrUndefined(r.slump ?? data.slump),
    airContent: numOrUndefined(r.air_content ?? data.airContent),
    unitWeight: numOrUndefined(data.unitWeight),
    cylindersMade: numOrUndefined(r.cylinders_made ?? data.cylindersMade),
    truckNumber: data.truckNumber,
    ticketNumber: data.ticketNumber,
    batchTime: data.batchTime,
    sampleTime: data.sampleTime,
    testAgeDays: data.testAgeDays,
    cylinderId: data.cylinderId,
    breakDate: data.breakDate,
    designStrengthPsi: numOrUndefined(data.designStrengthPsi),
    breakStrengthPsi: numOrUndefined(data.breakStrengthPsi),
    loadLbs: numOrUndefined(data.loadLbs),
    averageStrengthPsi: numOrUndefined(data.averageStrengthPsi),
    breakResult: data.breakResult,
    notes: r.notes ?? data.notes ?? '',
  };
}
